import { Link, Meta, MetaProvider, Title } from "@solidjs/meta";
import { Router } from "@solidjs/router";
import { FileRoutes } from "@solidjs/start/router";
import { Show, Suspense, onMount } from "solid-js";
import { isOnline } from "~/stores/networkStore";
import { initializeVaultStore } from "~/stores/vaultStore";
import { initializeTaskStore } from "~/stores/taskStore";
import { initializeSync } from "~/lib/sync";
import "./index.css";

export default function App() {
  onMount(async () => {
    await initializeVaultStore();
    await initializeTaskStore();

    if (typeof window !== "undefined") {
      void initializeSync();
    }
  });

  return (
    <Router
      root={props => (
        <MetaProvider>
          <Title>FocusFlow</Title>
          <Meta name="theme-color" content="#292524" />
          <Link rel="manifest" href="/manifest.json" />
          <Show when={!isOnline()}>
            <div class="fixed top-0 left-0 right-0 bg-stone-600 text-white text-center py-2 px-4 text-sm font-semibold z-50" role="status">
              You're offline. Local tasks still work. AI breakdown and sync will reconnect later.
            </div>
          </Show>
          <Suspense>{props.children}</Suspense>
        </MetaProvider>
      )}
    >
      <FileRoutes />
    </Router>
  );
}

import { Component, Show, createEffect, createSignal } from "solid-js";
import QRCode from "qrcode";

type QRDisplayProps = {
  joinUrl: string;
};

export const QRDisplay: Component<QRDisplayProps> = (props) => {
  const [qrDataUrl, setQrDataUrl] = createSignal<string>("");
  const [error, setError] = createSignal<string | null>(null);

  createEffect(() => {
    setQrDataUrl("");
    setError(null);

    void QRCode.toDataURL(props.joinUrl, {
      width: 300,
      margin: 2,
      color: {
        dark: "#292524",
        light: "#ffffff",
      },
    })
      .then(setQrDataUrl)
      .catch((err) => {
        setError(err instanceof Error ? err.message : "Failed to generate QR code");
      });
  });

  return (
    <div class="flex w-full flex-col items-center gap-4">
      <Show when={error()}>
        <p class="text-sm text-red-600">{error()}</p>
      </Show>
      <Show when={!error() && qrDataUrl()}>
        <img
          src={qrDataUrl()}
          alt="Vault pairing QR code"
          class="w-full max-w-[300px] rounded-2xl border border-stone-200"
        />
      </Show>
      <p class="text-center text-xs text-stone-500">
        This QR contains the full join link for this vault.
      </p>
    </div>
  );
};

import { createContext, useContext, type JSX, type ParentComponent, Show, batch, onCleanup } from "solid-js";
import { createStore } from "solid-js/store";
import { Portal } from "solid-js/web";
import { listSortMode } from "~/stores/preferencesStore";

export type DropPosition = "above" | "below" | "inside" | null;

type DragState = {
  status: "IDLE" | "PRESSED" | "DRAGGING" | "DROPPING";
  draggedId: string | null;
  targetId: string | null;
  dropPosition: DropPosition;
  startCoord: { x: number; y: number };
  currentCoord: { x: number; y: number };
  grabOffset: { x: number; y: number };
  originalRect: DOMRect | null;
};

type DragContextValue = {
  state: DragState;
  startDrag: (event: PointerEvent, id: string, el: HTMLElement) => void;
};

type DragProviderProps = {
  onDrop: (draggedId: string, targetId: string, position: Exclude<DropPosition, null>) => void;
  renderOverlay?: (id: string | null) => JSX.Element | null;
};

const DragContext = createContext<DragContextValue>();

const MOVEMENT_THRESHOLD = 5;
const HOT_ZONE = 100;

const calculateDropPosition = (pointerY: number, rect: DOMRect): Exclude<DropPosition, null> => {
  const relativeY = (pointerY - rect.top) / rect.height;
  if (relativeY < 0.25) return "above";
  if (relativeY > 0.75) return "below";
  return "inside";
};

export const DragProvider: ParentComponent<DragProviderProps> = (props) => {
  const [state, setState] = createStore<DragState>({
    status: "IDLE",
    draggedId: null,
    targetId: null,
    dropPosition: null,
    startCoord: { x: 0, y: 0 },
    currentCoord: { x: 0, y: 0 },
    grabOffset: { x: 0, y: 0 },
    originalRect: null,
  });

  let autoScrollFrame: number | undefined;
  let announcerTimeout: number | undefined;

  const announce = (message: string) => {
    const announcer = document.getElementById("dnd-announcer");
    if (!announcer) return;
    announcer.textContent = message;
    if (announcerTimeout) {
      clearTimeout(announcerTimeout);
    }
    announcerTimeout = window.setTimeout(() => {
      announcer.textContent = "";
    }, 800);
  };

  const startAutoScroll = () => {
    const loop = () => {
      if (state.status !== "DRAGGING") return;

      const { y } = state.currentCoord;
      const height = window.innerHeight;

      if (y > height - HOT_ZONE) {
        window.scrollBy(0, 6 + (y - (height - HOT_ZONE)) / 8);
      } else if (y < HOT_ZONE) {
        window.scrollBy(0, -(6 + (HOT_ZONE - y) / 8));
      }

      autoScrollFrame = requestAnimationFrame(loop);
    };
    loop();
  };

  const resetState = () => {
    batch(() => {
      setState({
        status: "IDLE",
        draggedId: null,
        targetId: null,
        dropPosition: null,
        startCoord: { x: 0, y: 0 },
        currentCoord: { x: 0, y: 0 },
        grabOffset: { x: 0, y: 0 },
        originalRect: null,
      });
    });
  };

  const handlePointerMove = (event: PointerEvent) => {
    if (state.status === "PRESSED") {
      const dist = Math.hypot(
        event.clientX - state.startCoord.x,
        event.clientY - state.startCoord.y,
      );

      if (dist > MOVEMENT_THRESHOLD) {
        batch(() => {
          setState("status", "DRAGGING");
          setState("currentCoord", { x: event.clientX, y: event.clientY });
        });
        startAutoScroll();
        announce("Dragging");
      }
      return;
    }

    if (state.status !== "DRAGGING") return;

    event.preventDefault();
    setState("currentCoord", { x: event.clientX, y: event.clientY });

    const targets = document.elementsFromPoint(event.clientX, event.clientY);
    const targetEl = targets.find((el) => el.hasAttribute("data-task-id")) as HTMLElement | undefined;

    if (!targetEl) {
      setState("targetId", null);
      setState("dropPosition", null);
      return;
    }

    const targetId = targetEl.getAttribute("data-task-id");
    if (!targetId || targetId === state.draggedId) return;

    const rect = targetEl.getBoundingClientRect();
    const position = calculateDropPosition(event.clientY, rect);

    batch(() => {
      setState("targetId", targetId);
      setState("dropPosition", position);
    });
  };

  const finishDrag = (event: PointerEvent) => {
    if (autoScrollFrame) cancelAnimationFrame(autoScrollFrame);
    window.removeEventListener("pointermove", handlePointerMove);
    window.removeEventListener("pointerup", finishDrag);

    if (state.status === "DRAGGING" && state.targetId && state.dropPosition) {
      props.onDrop(state.draggedId!, state.targetId, state.dropPosition);
    }

    if (state.status === "DRAGGING") {
      setState("status", "DROPPING");
      announce("Drop complete");
      window.setTimeout(resetState, 220);
    } else {
      resetState();
    }

    if (event.target instanceof Element) {
      event.target.releasePointerCapture(event.pointerId);
    }
  };

  const startDrag = (event: PointerEvent, id: string, el: HTMLElement) => {
    if (listSortMode() !== "manual") {
      announce("Switch to manual sort to reorder tasks");
      return;
    }

    event.preventDefault();
    event.stopPropagation();
    el.setPointerCapture(event.pointerId);

    const rect = el.closest("[data-task-id]")?.getBoundingClientRect() ?? el.getBoundingClientRect();

    batch(() => {
      setState({
        status: "PRESSED",
        draggedId: id,
        targetId: null,
        dropPosition: null,
        startCoord: { x: event.clientX, y: event.clientY },
        currentCoord: { x: event.clientX, y: event.clientY },
        grabOffset: { x: event.clientX - rect.left, y: event.clientY - rect.top },
        originalRect: rect,
      });
    });

    window.addEventListener("pointermove", handlePointerMove, { passive: false });
    window.addEventListener("pointerup", finishDrag);
  };

  onCleanup(() => {
    if (autoScrollFrame) cancelAnimationFrame(autoScrollFrame);
    if (announcerTimeout) clearTimeout(announcerTimeout);
    window.removeEventListener("pointermove", handlePointerMove);
    window.removeEventListener("pointerup", finishDrag);
  });

  const overlayStyle = () => {
    if (!state.originalRect) return {};

    const common = {
      width: `${state.originalRect.width}px`,
      "z-index": "9999",
      "pointer-events": "none",
      transition: "transform 160ms cubic-bezier(0.25, 0.9, 0.3, 1), opacity 160ms ease",
    } as const;

    if (state.status === "DROPPING") {
      return {
        ...common,
        transform: `translate3d(${state.originalRect.left}px, ${state.originalRect.top}px, 0) scale(1)`,
        opacity: 0.6,
      };
    }

    const x = state.currentCoord.x - state.grabOffset.x;
    const y = state.currentCoord.y - state.grabOffset.y;

    return {
      ...common,
      transform: `translate3d(${x}px, ${y}px, 0) scale(${state.status === "PRESSED" ? 0.985 : 1.01})`,
      opacity: state.status === "PRESSED" ? 0.75 : 1,
    };
  };

  return (
    <DragContext.Provider value={{ state, startDrag }}>
      {props.children}
      <Portal>
        <Show when={state.status !== "IDLE"}>
          <div
            class="drag-overlay"
            style={{
              position: "fixed",
              top: "0",
              left: "0",
              ...overlayStyle(),
            }}
          >
            <Show when={props.renderOverlay} fallback={
              <div class="drag-overlay__card">
                Dragging
              </div>
            }>
              {props.renderOverlay ? props.renderOverlay(state.draggedId) : null}
            </Show>
          </div>
        </Show>
        <div id="dnd-announcer" class="sr-only" aria-live="assertive" role="status" />
      </Portal>
    </DragContext.Provider>
  );
};

export const useDrag = () => {
  const ctx = useContext(DragContext);
  if (!ctx) throw new Error("useDrag must be used within DragProvider");
  return ctx;
};

import { fireEvent, render, screen } from "@solidjs/testing-library";
import { afterEach, describe, expect, it, vi } from "vitest";
import TaskItem from "./TaskItem";

const { updateTask } = vi.hoisted(() => ({
  updateTask: vi.fn(),
}));

vi.mock("~/stores/taskStore", () => ({
  deleteTask: vi.fn(),
  updateTask,
}));

vi.mock("./DragProvider", () => ({
  useDrag: () => ({
    startDrag: vi.fn(),
  }),
}));

describe("TaskItem due date editing", () => {
  afterEach(() => {
    vi.clearAllMocks();
  });

  it("opens an inline date input when the date badge is clicked", async () => {
    render(() => (
      <TaskItem
        id="task-1"
        parentId={null}
        workspaceId="default"
        text="Test task"
        completed={false}
        createdAt={1}
        updatedAt={1}
        dueAt={null}
        rank="0|aaa:"
        isStalled={false}
      />
    ));

    await fireEvent.click(screen.getByRole("button", { name: "Set due date" }));

    expect(screen.getByLabelText("Choose due date")).toBeInTheDocument();
  });

  it("persists the chosen due date", async () => {
    render(() => (
      <TaskItem
        id="task-1"
        parentId={null}
        workspaceId="default"
        text="Test task"
        completed={false}
        createdAt={1}
        updatedAt={1}
        dueAt={null}
        rank="0|aaa:"
        isStalled={false}
      />
    ));

    await fireEvent.click(screen.getByRole("button", { name: "Set due date" }));
    await fireEvent.change(screen.getByLabelText("Choose due date"), {
      target: { value: "2026-04-12" },
    });

    expect(updateTask).toHaveBeenCalledWith("task-1", { dueAt: Date.UTC(2026, 3, 12) });
  });
});

import { Show, createEffect, createSignal, on, onCleanup } from "solid-js";
import { Portal } from "solid-js/web";
import GripVertical from "lucide-solid/icons/grip-vertical";
import Trash2 from "lucide-solid/icons/trash-2";
import Calendar from "lucide-solid/icons/calendar";
import Check from "lucide-solid/icons/check";
import { formatDateInputValue, formatDueDateLabel, normalizeDateOnlyInput } from "~/lib/dates";
import { deleteTask, updateTask } from "~/stores/taskStore";
import type { Task } from "~/stores/taskStore";
import { useDrag } from "./DragProvider";

type TaskItemProps = Task & {
  dragActivators?: Record<string, (event: HTMLElementEventMap[keyof HTMLElementEventMap]) => void>;
};

export default function TaskItem(props: TaskItemProps) {
  const drag = useDrag();
  const [isEditing, setIsEditing] = createSignal(false);
  const [isEditingDueDate, setIsEditingDueDate] = createSignal(false);
  const [dueDateAnchor, setDueDateAnchor] = createSignal<{ top: number; left: number; width: number; height: number } | null>(null);
  const [draft, setDraft] = createSignal(props.text);
  let inputRef: HTMLTextAreaElement | undefined;
  let dueDateInputRef: HTMLInputElement | undefined;
  let dueDateButtonRef: HTMLButtonElement | undefined;

  createEffect(on(isEditing, (editing) => {
    if (editing && inputRef) {
      inputRef.style.height = 'auto';
      inputRef.style.height = inputRef.scrollHeight + 'px';

      queueMicrotask(() => {
        inputRef?.focus();
        inputRef?.select();
      });
    }
  }));

  const updateDueDateAnchor = () => {
    if (!dueDateButtonRef) {
      return;
    }

    const rect = dueDateButtonRef.getBoundingClientRect();
    setDueDateAnchor({
      top: rect.top,
      left: rect.left,
      width: rect.width,
      height: rect.height,
    });
  };

  const closeDueDateEditor = () => {
    setIsEditingDueDate(false);
    setDueDateAnchor(null);
  };

  createEffect(() => {
    if (!isEditingDueDate()) {
      return;
    }

    updateDueDateAnchor();

    const handleViewportChange = () => {
      updateDueDateAnchor();
    };

    document.addEventListener("scroll", handleViewportChange, true);
    window.addEventListener("resize", handleViewportChange);

    let frameOne = 0;
    let frameTwo = 0;

    frameOne = window.requestAnimationFrame(() => {
      frameTwo = window.requestAnimationFrame(() => {
        dueDateInputRef?.showPicker?.() ?? dueDateInputRef?.focus();
      });
    });

    onCleanup(() => {
      if (frameOne) {
        window.cancelAnimationFrame(frameOne);
      }
      if (frameTwo) {
        window.cancelAnimationFrame(frameTwo);
      }
      document.removeEventListener("scroll", handleViewportChange, true);
      window.removeEventListener("resize", handleViewportChange);
    });
  });

  const save = () => {
    const next = draft().trim();
    setIsEditing(false);
    if (next && next !== props.text) {
      updateTask(props.id, { text: next });
    } else {
      setDraft(props.text);
    }
  };

  const cancel = () => {
    setDraft(props.text);
    setIsEditing(false);
  };

  const autoResize = (el: HTMLTextAreaElement) => {
    el.style.height = 'auto';
    el.style.height = el.scrollHeight + 'px';
  };

  const handleDueDateChange = (value: string) => {
    const dueAt = normalizeDateOnlyInput(value);
    updateTask(props.id, { dueAt });
    closeDueDateEditor();
  };

  return (
    <div class="relative w-full group/item">
      <div class="relative z-10 bg-white rounded-xl border border-stone-200 p-3.5 flex items-start gap-3 transition-all hover:shadow-md hover:border-stone-300">

        {/* Drag Handle */}
        <div 
          class="text-stone-300 cursor-grab active:cursor-grabbing mt-1.5 hover:text-stone-500 shrink-0 touch-none"
          role="button"
          aria-label="Drag to reorder"
          onPointerDown={(event) => drag.startDrag(event, props.id, event.currentTarget as HTMLElement)}
        >
          <GripVertical class="w-4 h-4" />
        </div>

        {/* Checkbox */}
        <div class="pt-1 shrink-0">
          <label class="relative flex items-center justify-center cursor-pointer group/check">
            <input 
              type="checkbox" 
              class="sr-only peer"
              checked={props.completed}
              onChange={(event) => updateTask(props.id, { completed: event.currentTarget.checked })}
            />
            <div class="w-5 h-5 border-2 border-stone-300 rounded-md transition-colors peer-checked:bg-stone-600 peer-checked:border-stone-600 group-hover/check:border-stone-400 flex items-center justify-center">
              <Check class="w-3 h-3 text-white opacity-0 peer-checked:opacity-100 transition-opacity pointer-events-none" stroke-width={3} />
            </div>
          </label>
        </div>

        {/* Content */}
        <div class="flex-1 min-w-0 flex flex-col gap-1">
          <div class="flex items-start justify-between gap-2">

            <Show when={!isEditing()} fallback={
              <textarea
                ref={inputRef}
                class="w-full bg-transparent font-medium text-lg leading-tight outline-none text-stone-800 resize-none overflow-hidden"
                rows={1}
                value={draft()}
                onInput={(event) => {
                  setDraft(event.currentTarget.value);
                  autoResize(event.currentTarget);
                }}
                onBlur={save}
                onKeyDown={(event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    save();
                  }
                  if (event.key === "Escape") {
                    event.preventDefault();
                    cancel();
                  }
                }}
              />
            }>
              <div 
                class={`w-full font-medium text-lg leading-tight text-stone-800 cursor-text break-words ${props.completed ? 'line-through text-stone-400' : ''}`}
                onClick={() => setIsEditing(true)}
              >
                {props.text}
              </div>
            </Show>

            {/* Actions */}
            <div class="flex items-start shrink-0 opacity-100 sm:opacity-0 sm:group-hover/item:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); deleteTask(props.id); }}
                class="text-stone-300 hover:text-red-400 p-1.5 rounded-md hover:bg-stone-100 transition-colors ml-1"
                title="Delete"
                aria-label="Delete task"
              >
                <Trash2 class="w-4 h-4" />
              </button>
            </div>
          </div>

          {/* Date Badge */}
          <div class="relative flex items-center">
            <button
              ref={dueDateButtonRef}
              type="button"
              onClick={() => setIsEditingDueDate(true)}
              class={`flex items-center gap-1.5 px-2 py-0.5 rounded text-xs font-medium transition-colors ${
                props.dueAt === null
                  ? "border border-transparent text-stone-300 opacity-80 hover:bg-stone-50 hover:text-stone-500"
                  : "border bg-stone-50 border-stone-200 text-stone-500 hover:border-stone-300"
              }`}
              aria-label={props.dueAt === null ? "Set due date" : "Edit due date"}
            >
              <Calendar class="w-3 h-3" />
              <span>{props.dueAt === null ? "Set date" : formatDueDateLabel(props.dueAt)}</span>
            </button>
          </div>
        </div>
      </div>

      <Show when={isEditingDueDate() && dueDateAnchor()}>
        {(anchor) => (
          <Portal>
            <input
              ref={dueDateInputRef}
              type="date"
              aria-label="Choose due date"
              class="fixed z-[90] opacity-0 pointer-events-none"
              style={{
                top: `${anchor().top}px`,
                left: `${anchor().left}px`,
                width: `${anchor().width}px`,
                height: `${anchor().height}px`,
              }}
              value={formatDateInputValue(props.dueAt)}
              onChange={(event) => handleDueDateChange(event.currentTarget.value)}
              onBlur={() => closeDueDateEditor()}
              onKeyDown={(event) => {
                if (event.key === "Escape") {
                  closeDueDateEditor();
                }
              }}
            />
          </Portal>
        )}
      </Show>
    </div>
  );
}

