    expect(normalizeDateOnlyInput("2026-04-08")).toBe(Date.UTC(2026, 3, 8));
  });

  it("rejects invalid calendar dates", () => {
    expect(normalizeDateOnlyInput("2026-02-30")).toBeNull();
  });
});

describe("normalizeDueDateValue", () => {
  it("normalizes ISO date strings without shifting the selected day", () => {
    expect(normalizeDueDateValue("2026-04-08")).toBe(Date.UTC(2026, 3, 8));
  });
});

describe("formatDueDateLabel", () => {
  it("renders the stored day without the previous-day timezone bug", () => {
    expect(formatDueDateLabel(Date.UTC(2026, 3, 8), new Date("2026-04-01T12:00:00Z"))).toBe("Apr 8");
  });

  it("uses today and tomorrow labels against the local calendar day", () => {
    const now = new Date("2026-04-08T12:00:00Z");

    expect(formatDueDateLabel(Date.UTC(2026, 3, 8), now)).toBe("Today");
    expect(formatDueDateLabel(Date.UTC(2026, 3, 9), now)).toBe("Tomorrow");
  });
});

const DAY_MS = 24 * 60 * 60 * 1000;
const DATE_ONLY_PATTERN = /^(\d{4})-(\d{2})-(\d{2})$/;

const isValidDateOnly = (year: number, monthIndex: number, day: number, timestamp: number) => {
  const date = new Date(timestamp);

  return date.getUTCFullYear() === year
    && date.getUTCMonth() === monthIndex
    && date.getUTCDate() === day;
};

const localDateOnlyTimestamp = (date: Date) =>
  Date.UTC(date.getFullYear(), date.getMonth(), date.getDate());

export const normalizeDateOnlyInput = (value: string): number | null => {
  const match = DATE_ONLY_PATTERN.exec(value.trim());
  if (!match) {
    return null;
  }

  const year = Number.parseInt(match[1] ?? "", 10);
  const month = Number.parseInt(match[2] ?? "", 10);
  const day = Number.parseInt(match[3] ?? "", 10);
  const timestamp = Date.UTC(year, month - 1, day);

  if (!isValidDateOnly(year, month - 1, day, timestamp)) {
    return null;
  }

  return timestamp;
};

export const normalizeDueDateValue = (value?: string | number | null): number | null => {
  if (value === null || value === undefined || value === "") {
    return null;
  }

  if (typeof value === "number") {
    return Number.isFinite(value) ? value : null;
  }

  const dateOnly = normalizeDateOnlyInput(value);
  if (dateOnly !== null) {
    return dateOnly;
  }

  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) {
    return null;
  }

  return Date.UTC(
    parsed.getUTCFullYear(),
    parsed.getUTCMonth(),
    parsed.getUTCDate(),
  );
};

export const formatDueDateLabel = (dueAt: number, now: Date = new Date()) => {
  const today = localDateOnlyTimestamp(now);
  if (dueAt === today) {
    return "Today";
  }

  if (dueAt === today + DAY_MS) {
    return "Tomorrow";
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    timeZone: "UTC",
  }).format(dueAt);
};

export const formatDateInputValue = (dueAt: number | null) => {
  if (dueAt === null) {
    return "";
  }

  return new Date(dueAt).toISOString().slice(0, 10);
};

import { createSignal } from "solid-js";
import { isServer } from "solid-js/web";
import type { DbRequest, DbRequestBody, DbResponse } from "./db.types";

let worker: Worker | null = null;
let nextId = 1;
let isReady = false;

const pending = new Map<number, { resolve: (data: any) => void; reject: (err: Error) => void }>();
const queue: Array<{ msg: DbRequest; resolve: (data: any) => void; reject: (err: Error) => void }> = [];

const [dbVersion, setDbVersion] = createSignal(0);

const handleMessage = (event: MessageEvent<DbResponse>) => {
  const msg = event.data;

  if (msg.type === 'change') {
    setDbVersion(v => v + 1);
    return;
  }

  const handler = pending.get(msg.id);
  if (!handler) return;
  pending.delete(msg.id);

  if (msg.type === 'error') {
    handler.reject(new Error(msg.message));
  } else {
    handler.resolve(msg.data);
  }
};

const postAndWait = <T = any>(msg: DbRequestBody): Promise<T> => {
  return new Promise((resolve, reject) => {
    const id = nextId++;
    const fullMsg = { ...msg, id } as DbRequest;

    if (!isReady && msg.type !== 'init') {
      queue.push({ msg: fullMsg, resolve, reject });
      return;
    }

    pending.set(id, { resolve, reject });
    worker!.postMessage(fullMsg);
  });
};

const flushQueue = () => {
  isReady = true;
  while (queue.length > 0) {
    const { msg, resolve, reject } = queue.shift()!;
    pending.set(msg.id, { resolve, reject });
    worker!.postMessage(msg);
  }
};

export const initDb = async (): Promise<void> => {
  if (isServer) {
    throw new Error("Database cannot be initialized on the server");
  }

  if (worker) return;

  worker = new Worker(new URL('../workers/db.worker.ts', import.meta.url), {
    type: 'module',
  });

  worker.onmessage = handleMessage;

  await postAndWait({ type: 'init' });
  flushQueue();
};

export const exec = (sql: string, params?: any[]): Promise<void> => {
  return postAndWait({ type: 'exec', sql, params });
};

export const query = <T = any>(sql: string, params?: any[]): Promise<T[]> => {
  return postAndWait<{ rows: T[] }>({ type: 'query', sql, params }).then(data => data?.rows ?? []);
};

export const exportDb = (): Promise<Uint8Array> => {
  return postAndWait<{ bytes: Uint8Array }>({ type: 'export' }).then(data => data.bytes);
};

export const importDb = (data: ArrayBuffer): Promise<void> => {
  return postAndWait({ type: 'import', data });
};

export { dbVersion };

export const closeDb = () => {
  if (worker) {
    worker.terminate();
    worker = null;
    isReady = false;
  }
};

// Message types for main thread ↔ worker communication

export type DbRequestBody =
  | { type: 'init' }
  | { type: 'exec'; sql: string; params?: any[] }
  | { type: 'query'; sql: string; params?: any[] }
  | { type: 'export' }
  | { type: 'import'; data: ArrayBuffer };

export type DbRequest = DbRequestBody & { id: number };

export type DbResponse =
  | { id: number; type: 'success'; data?: any }
  | { id: number; type: 'error'; message: string }
  | { type: 'change'; table: string };

