const PAIR_ROUTE = "/pair";

export const buildPairingHash = (vaultKey: string): string => {
  return `#vault=${encodeURIComponent(vaultKey)}`;
};

export const buildPairingUrl = (origin: string, vaultKey: string): string => {
  const pairUrl = new URL(PAIR_ROUTE, origin);
  return `${pairUrl.toString()}${buildPairingHash(vaultKey)}`;
};

export const parseVaultKeyFromHash = (hash: string): string | null => {
  const fragment = hash.startsWith("#") ? hash.slice(1) : hash;

  if (!fragment) {
    return null;
  }

  const params = new URLSearchParams(fragment);
  const vaultKey = params.get("vault");

  return vaultKey && vaultKey.length > 0 ? vaultKey : null;
};

export const clearPairingHash = (): void => {
  const url = new URL(window.location.href);
  url.hash = "";
  window.history.replaceState(window.history.state, "", `${url.pathname}${url.search}`);
};

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import Database from "better-sqlite3";
import { MAIN_VIEW_QUERY } from "./query";

let db: InstanceType<typeof Database>;

const CREATE_TABLE = `
  CREATE TABLE tasks (
    id TEXT PRIMARY KEY,
    parent_id TEXT,
    text TEXT NOT NULL,
    completed INTEGER NOT NULL DEFAULT 0,
    created_at INTEGER NOT NULL,
    updated_at INTEGER NOT NULL,
    due_at INTEGER,
    rank TEXT NOT NULL
  )
`;

const DAY = 24 * 60 * 60 * 1000;
const now = Date.now();
const eightDaysAgo = now - 8 * DAY;

const insert = (
  id: string,
  overrides: Record<string, any> = {},
) => {
  const defaults = {
    parent_id: null,
    text: `Task ${id}`,
    completed: 0,
    created_at: now,
    updated_at: now,
    due_at: null,
    rank: `0|${id}:`,
  };
  const row = { id, ...defaults, ...overrides };
  db.prepare(
    `INSERT INTO tasks (id, parent_id, text, completed, created_at, updated_at, due_at, rank)
     VALUES (@id, @parent_id, @text, @completed, @created_at, @updated_at, @due_at, @rank)`,
  ).run(row);
};

beforeEach(() => {
  db = new Database(":memory:");
  db.exec(CREATE_TABLE);
});

afterEach(() => {
  db.close();
});

describe("MAIN_VIEW_QUERY ordering", () => {
  it("stalled tasks appear before non-stalled incomplete tasks", () => {
    insert("stalled", { created_at: eightDaysAgo, updated_at: eightDaysAgo, rank: "0|bbb:" });
    insert("active", { rank: "0|aaa:" });

    const rows = db.prepare(MAIN_VIEW_QUERY).all() as any[];
    expect(rows[0].id).toBe("stalled");
    expect(rows[0].is_stalled).toBe(1);
    expect(rows[1].id).toBe("active");
    expect(rows[1].is_stalled).toBe(0);
  });

  it("completed tasks appear after incomplete tasks", () => {
    insert("done", { completed: 1, rank: "0|aaa:" });
    insert("todo", { completed: 0, rank: "0|bbb:" });

    const rows = db.prepare(MAIN_VIEW_QUERY).all() as any[];
    expect(rows[0].id).toBe("todo");
    expect(rows[1].id).toBe("done");
  });

  it("sibling order follows rank within stalled/non-stalled groups", () => {
    insert("b", { rank: "0|bbb:" });
    insert("a", { rank: "0|aaa:" });
    insert("stalled-b", { created_at: eightDaysAgo, updated_at: eightDaysAgo, rank: "0|sbb:" });
    insert("stalled-a", { created_at: eightDaysAgo, updated_at: eightDaysAgo, rank: "0|saa:" });

    const rows = db.prepare(MAIN_VIEW_QUERY).all() as any[];
    const ids = rows.map((r: any) => r.id);
    expect(ids).toEqual(["stalled-a", "stalled-b", "a", "b"]);
  });

  it("subtask hierarchy is preserved via parent_id grouping", () => {
    insert("parent", { rank: "0|aaa:" });
    insert("child-b", { parent_id: "parent", rank: "0|bbb:" });
    insert("child-a", { parent_id: "parent", rank: "0|aaa:" });
    insert("root-b", { rank: "0|bbb:" });

    const rows = db.prepare(MAIN_VIEW_QUERY).all() as any[];
    const ids = rows.map((r: any) => r.id);
    // Root tasks (parent_id NULL) sort first, then children grouped by parent_id
    expect(ids.indexOf("parent")).toBeLessThan(ids.indexOf("child-a"));
    expect(ids.indexOf("child-a")).toBeLessThan(ids.indexOf("child-b"));
  });
});

import { createEffect, createSignal, onCleanup } from "solid-js";
import { exec, query } from "./db";

export const MAIN_VIEW_QUERY = `
SELECT *,
  CASE
    WHEN updated_at = created_at
     AND created_at < (strftime('%s', 'now') * 1000 - 7*24*60*60*1000)
    THEN 1
    ELSE 0
  END as is_stalled
FROM tasks
WHERE workspace_id = ?
ORDER BY completed ASC, is_stalled DESC, parent_id ASC, rank ASC
`;

export const fetchMainViewTasks = <T = any>(workspaceId: string): Promise<T[]> =>
  query<T>(MAIN_VIEW_QUERY, [workspaceId]);

type QueryCallback = () => any;

export const createReactiveQuery = <T = any>(
  queryFn: QueryCallback,
  dependencies: any[] = []
) => {
  const [data, setData] = createSignal<T | null>(null);
  const [isLoading, setIsLoading] = createSignal(true);
  const [error, setError] = createSignal<Error | null>(null);

  let isMounted = true;

  const executeQuery = async () => {
    if (!isMounted) return;

    try {
      setIsLoading(true);
      setError(null);
      const result = await queryFn();

      if (isMounted) {
        setData(result);
      }
    } catch (err) {
      if (isMounted) {
        setError(err as Error);
      }
    } finally {
      if (isMounted) {
        setIsLoading(false);
      }
    }
  };

  createEffect(() => {
    executeQuery();
  });

  onCleanup(() => {
    isMounted = false;
  });

  return { data, isLoading, error, refetch: executeQuery };
};

export const createLiveQuery = <T = any>(sql: string, params: any[] = []) => {
  const [data, setData] = createSignal<T[]>([]);
  const [isLoading, setIsLoading] = createSignal(true);

  const executeQuery = async () => {
    try {
      const result = await query<T>(sql, params);
      setData(result);
    } catch (err) {
      console.error("Live query error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  executeQuery();

  return { data, isLoading, refetch: executeQuery };
};

export type RateLimitPolicy = {
  id: string;
  maxRequests: number;
  windowMs: number;
};

type RateLimitBucket = {
  count: number;
  resetAt: number;
};

type RateLimitResult =
  | {
      allowed: true;
    }
  | {
      allowed: false;
      retryAfterMs: number;
    };

const UNKNOWN_CLIENT = "unknown";
const UNKNOWN_USER_AGENT = "unknown";
const USER_AGENT_MAX_LENGTH = 200;
const PRUNE_INTERVAL = 100;

const rateLimitBuckets = new Map<string, RateLimitBucket>();
let accessCount = 0;

const normalizeUserAgent = (value: string | null) => {
  const normalized = value?.trim().toLowerCase().replace(/\s+/g, " ") ?? "";
  return normalized ? normalized.slice(0, USER_AGENT_MAX_LENGTH) : UNKNOWN_USER_AGENT;
};

const normalizeClientAddress = (value: string | null | undefined) => {
  const normalized = value?.trim().replace(/^"|"$/g, "").replace(/^\[|\]$/g, "") ?? "";
  return normalized || UNKNOWN_CLIENT;
};

const parseForwardedHeader = (value: string | null) => {
  if (!value) {
    return null;
  }

  const firstEntry = value.split(",")[0]?.trim() ?? "";
  const match = firstEntry.match(/for=(?:"?\[?([^;\]",]+)\]?)/i);
  return normalizeClientAddress(match?.[1] ?? null);
};

const getRequestClientAddress = (request: Request, fallbackAddress?: string) => {
  const forwarded = parseForwardedHeader(request.headers.get("forwarded"));
  if (forwarded && forwarded !== UNKNOWN_CLIENT) {
    return forwarded;
  }

  const forwardedFor = request.headers.get("x-forwarded-for");
  if (forwardedFor) {
    const firstForwarded = normalizeClientAddress(forwardedFor.split(",")[0]);
    if (firstForwarded !== UNKNOWN_CLIENT) {
      return firstForwarded;
    }
  }

  const proxyHeaders = ["cf-connecting-ip", "x-real-ip"] as const;
  for (const header of proxyHeaders) {
    const value = normalizeClientAddress(request.headers.get(header));
    if (value !== UNKNOWN_CLIENT) {
      return value;
    }
  }

  return normalizeClientAddress(fallbackAddress);
};

const getBucketState = (bucketId: string, policy: RateLimitPolicy, now: number) => {
  const current = rateLimitBuckets.get(bucketId);
  if (!current || current.resetAt <= now) {
    return {
      count: 0,
      resetAt: now + policy.windowMs,
    };
  }

  return current;
};

const pruneExpiredBuckets = (now: number) => {
  accessCount += 1;
  if (accessCount % PRUNE_INTERVAL !== 0) {
    return;
  }

  for (const [bucketId, bucket] of rateLimitBuckets) {
    if (bucket.resetAt <= now) {
      rateLimitBuckets.delete(bucketId);
    }
  }
};

export const buildRateLimitBucketKey = (
  request: Request,
  routeFamily: string,
  clientAddress?: string,
) => {
  const ip = getRequestClientAddress(request, clientAddress);
  const userAgent = normalizeUserAgent(request.headers.get("user-agent"));

  return `${routeFamily}:${ip}:${userAgent}`;
};

export const consumeRateLimit = (
  bucketKey: string,
  policies: readonly RateLimitPolicy[],
  now = Date.now(),
): RateLimitResult => {
  pruneExpiredBuckets(now);

  const nextBuckets = new Map<string, RateLimitBucket>();

  for (const policy of policies) {
    const bucketId = `${policy.id}:${bucketKey}`;
    const current = getBucketState(bucketId, policy, now);

    if (current.count + 1 > policy.maxRequests) {
      return {
        allowed: false,
        retryAfterMs: Math.max(current.resetAt - now, 0),
      };
    }

    nextBuckets.set(bucketId, {
      count: current.count + 1,
      resetAt: current.resetAt,
    });
  }

  for (const [bucketId, bucket] of nextBuckets) {
    rateLimitBuckets.set(bucketId, bucket);
  }

  return { allowed: true };
};

export const createRateLimitResponse = (message: string, retryAfterMs: number) => {
  const retryAfterSeconds = Math.max(1, Math.ceil(retryAfterMs / 1000));

  return Response.json(
    { error: message },
    {
      status: 429,
      headers: {
        "retry-after": String(retryAfterSeconds),
      },
    },
  );
};

export const resetRateLimitStore = () => {
  rateLimitBuckets.clear();
  accessCount = 0;
};

import { describe, expect, it } from "vitest";
import {
  OFFLINE_DOCUMENT_PATHS,
  shouldHandleOfflineNavigation,
  toNavigationCacheKey,
} from "./serviceWorkerRouting";

describe("serviceWorkerRouting", () => {
  it("tracks the known offline-capable document routes", () => {
    expect(OFFLINE_DOCUMENT_PATHS).toEqual(["/", "/settings", "/pair"]);
  });

  it("allows same-origin navigation requests for app routes", () => {
    expect(
      shouldHandleOfflineNavigation(
        "navigate",
        new URL("https://app.test/settings"),
        "https://app.test",
      ),
    ).toBe(true);
  });

  it("rejects api requests, static files, and cross-origin navigations", () => {
    expect(
      shouldHandleOfflineNavigation(
        "navigate",
        new URL("https://app.test/api/sync/vault/list"),
        "https://app.test",
      ),
    ).toBe(false);

    expect(
      shouldHandleOfflineNavigation(
        "navigate",
        new URL("https://app.test/icon-192.png"),
        "https://app.test",
      ),
    ).toBe(false);

    expect(
      shouldHandleOfflineNavigation(
        "navigate",
        new URL("https://cdn.test/settings"),
        "https://app.test",
      ),
    ).toBe(false);
  });

  it("normalizes navigation cache keys to pathname only", () => {
    expect(toNavigationCacheKey(new URL("https://app.test/pair?from=qr"))).toBe("/pair");
  });
});

export const OFFLINE_DOCUMENT_PATHS = ["/", "/settings", "/pair"] as const;

const STATIC_FILE_PATTERN = /\/[^/?]+\.[^/]+$/;

export const shouldHandleOfflineNavigation = (requestMode: string, url: URL, scopeOrigin: string) => {
  if (requestMode !== "navigate") {
    return false;
  }

  if (url.origin !== scopeOrigin) {
    return false;
  }

  if (url.pathname.startsWith("/api/")) {
    return false;
  }

  if (url.pathname === "/manifest.json") {
    return false;
  }

  if (url.pathname.startsWith("/_build/")) {
    return false;
  }

  return !STATIC_FILE_PATTERN.test(url.pathname);
};

export const toNavigationCacheKey = (url: URL) => url.pathname || "/";

import { createSignal } from "solid-js";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

type VaultStateMock = {
  vaultKey: string | null;
  vaultPath: string | null;
  deviceId: string | null;
  isPaired: boolean;
  requiresRemoteBootstrap: boolean;
};

type StoreRecord = Record<string, unknown>;
type StoreDefinition = {
  keyPath: string;
  autoIncrement: boolean;
  nextKey: number;
  records: Map<unknown, StoreRecord>;
};

const textEncoder = new TextEncoder();

const makeSuccessRequest = <T>(result: T) => {
  const request = {
    result,
    error: null,
    onsuccess: null as ((event: Event) => void) | null,
    onerror: null as ((event: Event) => void) | null,
  };

  queueMicrotask(() => {
    request.onsuccess?.(new Event("success"));
  });

  return request;
};

class FakeObjectStore {
  constructor(private readonly store: StoreDefinition) {}

  put(value: StoreRecord) {
    this.store.records.set(value[this.store.keyPath], structuredClone(value));
    return makeSuccessRequest(value);
  }

  get(key: unknown) {
    return makeSuccessRequest(this.store.records.get(key));
  }

  getAll() {
    return makeSuccessRequest([...this.store.records.values()].map((value) => structuredClone(value)));
  }

  delete(key: unknown) {
    this.store.records.delete(key);
    return makeSuccessRequest(undefined);
  }

  add(value: StoreRecord) {
    const nextValue = structuredClone(value);

    if (this.store.autoIncrement) {
      nextValue[this.store.keyPath] = this.store.nextKey++;
    }

    this.store.records.set(nextValue[this.store.keyPath], nextValue);
    return makeSuccessRequest(nextValue[this.store.keyPath]);
  }
}

class FakeDatabase {
  readonly stores = new Map<string, StoreDefinition>();
  readonly objectStoreNames = {
    contains: (name: string) => this.stores.has(name),
  };

  createObjectStore(name: string, options?: { keyPath?: string; autoIncrement?: boolean }) {
    const store: StoreDefinition = {
      keyPath: options?.keyPath ?? "id",
      autoIncrement: options?.autoIncrement ?? false,
      nextKey: 1,
      records: new Map(),
    };

    this.stores.set(name, store);
    return new FakeObjectStore(store);
  }

  transaction(name: string) {
    const store = this.stores.get(name);
    if (!store) {
      throw new Error(`Missing store: ${name}`);
    }

    return {
      objectStore: () => new FakeObjectStore(store),
    };
  }
}

const installFakeIndexedDb = () => {
  const databases = new Map<string, FakeDatabase>();

  Object.defineProperty(globalThis, "indexedDB", {
    configurable: true,
    value: {
      open: (name: string) => {
        const request = {
          result: null as FakeDatabase | null,
          error: null,
          onsuccess: null as ((event: Event) => void) | null,
          onerror: null as ((event: Event) => void) | null,
          onupgradeneeded: null as ((event: IDBVersionChangeEvent) => void) | null,
        };

        queueMicrotask(() => {
          let db = databases.get(name);
          const isNew = !db;

          if (!db) {
            db = new FakeDatabase();
            databases.set(name, db);
          }

          request.result = db;

          if (isNew) {
            request.onupgradeneeded?.({ target: { result: db } } as unknown as IDBVersionChangeEvent);
          }

          request.onsuccess?.(new Event("success"));
        });

        return request;
      },
    },
  });
};

const encodeJson = (value: unknown) => textEncoder.encode(JSON.stringify(value));

describe("sync", () => {
  let vaultState: VaultStateMock;
  let resolveRemoteBootstrap: ReturnType<typeof vi.fn>;
  let execMock: ReturnType<typeof vi.fn>;
  let queryMock: ReturnType<typeof vi.fn>;
  let fetchMock: ReturnType<typeof vi.fn>;
  let setDbVersion: (value: number) => void;
  let localChanges: Array<Record<string, unknown>>;
  const workspacesCount = 0;
  const tasksCount = 0;

  beforeEach(() => {
    vi.resetModules();
    vi.restoreAllMocks();
    installFakeIndexedDb();

    Object.defineProperty(window.navigator, "onLine", {
      configurable: true,
      value: true,
    });

    vaultState = {
      vaultKey: "secret",
      vaultPath: "vault-a",
      deviceId: "device-a",
      isPaired: true,
      requiresRemoteBootstrap: false,
    };

    resolveRemoteBootstrap = vi.fn(() => Promise.resolve().then(() => {
      vaultState.requiresRemoteBootstrap = false;
    }));

    execMock = vi.fn(() => Promise.resolve());
    localChanges = [];

    const [version, applyVersion] = createSignal(0);
    setDbVersion = applyVersion;

    queryMock = vi.fn((sql: string) => {
      if (sql.includes('FROM "crsql_changes"')) {
        return Promise.resolve(localChanges);
      }

      if (sql.includes("SELECT COUNT(*) as count FROM workspaces")) {
        return Promise.resolve([{ count: workspacesCount }]);
      }

      if (sql.includes("SELECT COUNT(*) as count FROM tasks")) {
        return Promise.resolve([{ count: tasksCount }]);
      }

      return Promise.resolve([]);
    });

    vi.doMock("~/stores/vaultStore", () => ({
      vaultState,
      resolveRemoteBootstrap,
    }));

    vi.doMock("~/lib/db", () => ({
      dbVersion: version,
      exec: execMock,
      query: queryMock,
    }));

    vi.doMock("~/lib/crypto", () => ({
      importKey: vi.fn(() => Promise.resolve({ type: "key" })),
      encryptData: vi.fn((_key: unknown, payload: Uint8Array) => Promise.resolve(payload)),
      decryptData: vi.fn((_key: unknown, payload: Uint8Array) => Promise.resolve(payload)),
    }));

    fetchMock = vi.fn((input: RequestInfo | URL) => {
      const url =
        typeof input === "string"
          ? new URL(input, "http://localhost")
          : input instanceof URL
            ? input
            : new URL(input.url);

      if (url.pathname === "/api/sync/vault-a/snapshots/list") {
        return Promise.resolve(Response.json({
          snapshots: [{ key: "100-device-a.snapshot.bin", timestamp: 100 }],
        }));
      }

      if (url.pathname === "/api/sync/vault-b/snapshots/list") {
        return Promise.resolve(Response.json({ snapshots: [] }));
      }

      if (url.pathname === "/api/sync/vault-a/snapshots/download/100-device-a.snapshot.bin") {
        return Promise.resolve(new Response(encodeJson({
          workspaces: [{ id: "default", name: "Default", created_at: 1, updated_at: 1 }],
          tasks: [{ id: "task-1", parent_id: null, workspace_id: "default", text: "Imported", completed: 0, created_at: 1, updated_at: 1, due_at: null, rank: "0|aaa:" }],
        })));
      }

      if (url.pathname === "/api/sync/vault-a/list" || url.pathname === "/api/sync/vault-b/list") {
        return Promise.resolve(Response.json({ changesets: [] }));
      }

      if (url.pathname === "/api/sync/vault-a/upload" || url.pathname === "/api/sync/vault-b/upload") {
        return Promise.resolve(Response.json({ timestamp: 200 }));
      }

      if (url.pathname === "/api/sync/vault-a/snapshots/upload") {
        return Promise.resolve(Response.json({ timestamp: 111 }));
      }

      if (url.pathname === "/api/sync/vault-b/snapshots/upload") {
        return Promise.resolve(Response.json({ timestamp: 222 }));
      }

      return Promise.reject(new Error(`Unexpected fetch: ${url.toString()}`));
    });

    vi.stubGlobal("fetch", fetchMock);
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.unstubAllGlobals();
  });

  it("bootstraps a joined device from the latest JSON snapshot", async () => {
    vaultState.requiresRemoteBootstrap = true;

    const { initializeSync, syncStateStore } = await import("./sync");
    await initializeSync();

    expect(execMock).toHaveBeenCalledWith("DELETE FROM tasks");
    expect(execMock).toHaveBeenCalledWith(
      "INSERT INTO workspaces (id, name, created_at, updated_at) VALUES (?, ?, ?, ?)",
      ["default", "Default", 1, 1],
    );
    expect(execMock).toHaveBeenCalledWith(
      expect.stringContaining("INSERT INTO tasks"),
      ["task-1", null, "default", "Imported", 0, 1, 1, null, "0|aaa:"],
    );
    expect(syncStateStore.lastSyncTimestamp).toBe(100);
    expect(resolveRemoteBootstrap).toHaveBeenCalledTimes(1);
  });

  it("scopes metadata by vault path when switching vaults", async () => {
    vaultState.requiresRemoteBootstrap = true;
    const { initializeSync, syncStateStore } = await import("./sync");

    await initializeSync();
    expect(syncStateStore.lastSyncTimestamp).toBe(100);

    vaultState.vaultPath = "vault-b";
    vaultState.vaultKey = "secret-b";
    vaultState.requiresRemoteBootstrap = true;
    await initializeSync();

    expect(syncStateStore.lastSyncTimestamp).toBeNull();

    vaultState.vaultPath = "vault-a";
    vaultState.vaultKey = "secret";
    vaultState.requiresRemoteBootstrap = false;
    await initializeSync();

    expect(syncStateStore.lastSyncTimestamp).toBe(100);
  });

  it("uploads local crsql_changes after a debounced db change", async () => {
    vi.useFakeTimers();

    localChanges = [
      {
        table: "tasks",
        pk: "task-1",
        cid: "text",
        val: "Write docs",
        col_version: 1,
        db_version: 3,
        site_id: "site-a",
        cl: 1,
        seq: 0,
      },
    ];

    const { initializeSync, syncStateStore } = await import("./sync");
    await initializeSync();

    setDbVersion(1);
    await Promise.resolve();
    await vi.advanceTimersByTimeAsync(801);

    expect(queryMock).toHaveBeenCalledWith(
      expect.stringContaining('AND ("site_id" = crsql_site_id() OR "site_id" IS NULL)'),
      [0],
    );
    expect(fetchMock).toHaveBeenCalledWith("/api/sync/vault-a/upload", expect.any(Object));
    expect(syncStateStore.lastSyncTimestamp).toBe(200);
  });
});

import { createEffect, createRoot } from "solid-js";
import { createStore, produce } from "solid-js/store";
import { dbVersion, exec, query } from "~/lib/db";
import { decryptData, encryptData, importKey } from "~/lib/crypto";
import { resolveRemoteBootstrap, vaultState } from "~/stores/vaultStore";

type SyncStatus = "idle" | "syncing" | "error";

type EncodedBytes = {
  type: "bytes";
  base64: string;
};

type EncodedValue = string | number | boolean | null | EncodedBytes;

type SyncChangeRow = {
  table: string;
  pk: EncodedValue;
  cid: string;
  val: EncodedValue;
  col_version: number;
  db_version: number;
  site_id: EncodedValue;
  cl: number;
  seq: number;
};

type SyncChangesPayload = {
  changes: SyncChangeRow[];
  maxDbVersion: number;
};

type SnapshotWorkspaceRow = {
  id: string;
  name: string;
  created_at: number;
  updated_at: number;
};

type SnapshotTaskRow = {
  id: string;
  parent_id: string | null;
  workspace_id: string;
  text: string;
  completed: number;
  created_at: number;
  updated_at: number;
  due_at: number | null;
  rank: string;
};

type SyncSnapshotPayload = {
  workspaces: SnapshotWorkspaceRow[];
  tasks: SnapshotTaskRow[];
};

type SyncQueueItem = {
  id?: number;
  vaultPath: string;
  deviceId: string;
  payload: Uint8Array;
  maxDbVersion: number;
  timestamp: number;
};

type SyncState = {
  status: SyncStatus;
  lastSyncTimestamp: number | null;
  offlineQueue: Array<{ vaultPath: string; maxDbVersion: number; timestamp: number }>;
};

type DownloadResult = {
  downloadedSnapshot: boolean;
  downloadedChangesetCount: number;
};

const SYNC_IDB_NAME = "sync_store";
const SYNC_IDB_VERSION = 2;
const LAST_SYNC_TIMESTAMP_KEY = "lastSyncTimestamp";
const LAST_REMOTE_TIMESTAMP_KEY = "lastRemoteTimestamp";
const LAST_UPLOADED_DB_VERSION_KEY = "lastUploadedDbVersion";
const LAST_SNAPSHOT_TIMESTAMP_KEY = "lastSnapshotTimestamp";
const CHANGESETS_SINCE_SNAPSHOT_KEY = "changesetsSinceSnapshot";
const AUTO_SYNC_DEBOUNCE_MS = 800;
const SNAPSHOT_INTERVAL_MS = 24 * 60 * 60 * 1000;
const SNAPSHOT_CHANGESET_THRESHOLD = 100;
const DEFAULT_WORKSPACE_ID = "default";
const DEFAULT_WORKSPACE_NAME = "Default";

const textEncoder = new TextEncoder();
const textDecoder = new TextDecoder();

let idb: IDBDatabase | null = null;
let activeVaultPath: string | null = null;
let activeSyncPromise: Promise<void> | null = null;
let autoSyncTimer: number | null = null;
let applyingRemoteSync = false;
let dbWatcherInitialized = false;
let wasOfflineWhileHidden = false;
let listenersInitialized = false;

const [syncState, setSyncState] = createStore<SyncState>({
  status: "idle",
  lastSyncTimestamp: null,
  offlineQueue: [],
});

const bytesToBase64 = (bytes: Uint8Array) =>
  btoa(Array.from(bytes, (byte) => String.fromCharCode(byte)).join(""));

const buildVaultApiPath = (vaultPath: string, ...segments: string[]) =>
  `/api/sync/${encodeURIComponent(vaultPath)}/${segments.map((segment) => encodeURIComponent(segment)).join("/")}`;

const base64ToBytes = (base64: string) => {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);

  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index);
  }

  return bytes;
};

const normalizeBytes = (value: unknown): Uint8Array | null => {
  if (value instanceof Uint8Array) {
    return value;
  }

  if (value instanceof ArrayBuffer) {
    return new Uint8Array(value);
  }

  if (ArrayBuffer.isView(value)) {
    return new Uint8Array(value.buffer.slice(value.byteOffset, value.byteOffset + value.byteLength));
  }

  return null;
};

const encodeSqliteValue = (value: unknown): EncodedValue => {
  if (value === null || typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return value;
  }

  const bytes = normalizeBytes(value);
  if (bytes) {
    return {
      type: "bytes",
      base64: bytesToBase64(bytes),
    };
  }

  throw new Error(`Unsupported SQLite value in sync payload: ${String(value)}`);
};

const decodeSqliteValue = (value: EncodedValue): string | number | boolean | null | Uint8Array => {
  if (typeof value === "object" && value !== null && "type" in value && value.type === "bytes") {
    return base64ToBytes(value.base64);
  }

  return value;
};

const encodeChangesPayload = (payload: SyncChangesPayload) =>
  textEncoder.encode(JSON.stringify(payload));

const decodeChangesPayload = (payload: Uint8Array): SyncChangesPayload =>
  JSON.parse(textDecoder.decode(payload)) as SyncChangesPayload;

const encodeSnapshotPayload = (payload: SyncSnapshotPayload) =>
  textEncoder.encode(JSON.stringify(payload));

const decodeSnapshotPayload = (payload: Uint8Array): SyncSnapshotPayload =>
  JSON.parse(textDecoder.decode(payload)) as SyncSnapshotPayload;

const getScopedSyncKey = (vaultPath: string, key: string) => `${vaultPath}:${key}`;

const initSyncIndexedDB = (): Promise<IDBDatabase> =>
  new Promise((resolve, reject) => {
    const request = indexedDB.open(SYNC_IDB_NAME, SYNC_IDB_VERSION);

    request.onerror = () => reject(new Error(request.error?.message ?? "Failed to open sync IndexedDB"));
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;

      if (!db.objectStoreNames.contains("sync")) {
        db.createObjectStore("sync", { keyPath: "key" });
      }

      if (!db.objectStoreNames.contains("syncQueue")) {
        db.createObjectStore("syncQueue", { keyPath: "id", autoIncrement: true });
      }
    };
  });

const setSyncIDBValue = async (key: string, value: unknown) => {
  if (!idb) {
    idb = await initSyncIndexedDB();
  }

  return new Promise<void>((resolve, reject) => {
    const transaction = idb!.transaction("sync", "readwrite");
    const store = transaction.objectStore("sync");
    const request = store.put({ key, value });

    request.onsuccess = () => resolve();
    request.onerror = () => reject(new Error(request.error?.message ?? `Failed to persist sync key ${key}`));
  });
};

const getSyncIDBValue = async <T,>(key: string): Promise<T | null> => {
  if (!idb) {
    idb = await initSyncIndexedDB();
  }

  return new Promise((resolve, reject) => {
    const transaction = idb!.transaction("sync", "readonly");
    const store = transaction.objectStore("sync");
    const request = store.get(key);

    request.onsuccess = () => {
      const result = request.result as { value: T } | undefined;
      resolve(result ? result.value : null);
    };
    request.onerror = () => reject(new Error(request.error?.message ?? `Failed to read sync key ${key}`));
  });
};

const setVaultSyncIDBValue = async (key: string, value: unknown, vaultPath = vaultState.vaultPath) => {
  if (!vaultPath) {
    return;
  }

  await setSyncIDBValue(getScopedSyncKey(vaultPath, key), value);
};

const getVaultSyncIDBValue = async <T,>(key: string, vaultPath = vaultState.vaultPath) => {
  if (!vaultPath) {
    return null;
  }

  return getSyncIDBValue<T>(getScopedSyncKey(vaultPath, key));
};

const addToSyncQueue = async (item: Omit<SyncQueueItem, "id">): Promise<void> => {
  if (!idb) {
    idb = await initSyncIndexedDB();
  }

  return new Promise((resolve, reject) => {
    const transaction = idb!.transaction("syncQueue", "readwrite");
    const store = transaction.objectStore("syncQueue");
    const request = store.add(item);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(new Error(request.error?.message ?? "Failed to queue sync payload"));
  });
};

const getSyncQueue = async (vaultPath?: string): Promise<SyncQueueItem[]> => {
  if (!idb) {
    idb = await initSyncIndexedDB();
  }

  return new Promise((resolve, reject) => {
    const transaction = idb!.transaction("syncQueue", "readonly");
    const store = transaction.objectStore("syncQueue");
    const request = store.getAll();

    request.onsuccess = () => {
      const items = (request.result as SyncQueueItem[]) ?? [];
      resolve(vaultPath ? items.filter((item) => item.vaultPath === vaultPath) : items);
    };
    request.onerror = () => reject(new Error(request.error?.message ?? "Failed to read sync queue"));
  });
};

const removeFromSyncQueue = async (id: number): Promise<void> => {
  if (!idb) {
    idb = await initSyncIndexedDB();
  }

  return new Promise((resolve, reject) => {
    const transaction = idb!.transaction("syncQueue", "readwrite");
    const store = transaction.objectStore("syncQueue");
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(new Error(request.error?.message ?? `Failed to remove queued item ${id}`));
  });
};

const registerBackgroundSync = async (): Promise<void> => {
  if (!navigator.onLine && "serviceWorker" in navigator) {
    try {
      const registration = await navigator.serviceWorker.ready;
      const syncManager = (registration as ServiceWorkerRegistration & {
        sync?: { register: (tag: string) => Promise<void> };
      }).sync;

      if (syncManager) {
        await syncManager.register("sync-tasks");
      }
    } catch (error) {
      console.warn("Background sync registration failed:", error);
    }
  }
};

const updateVisibleLastSync = async (timestamp: number) => {
  await setVaultSyncIDBValue(LAST_SYNC_TIMESTAMP_KEY, timestamp);
  setSyncState("lastSyncTimestamp", timestamp);
};

const hydrateSyncStateForCurrentVault = async () => {
  const vaultPath = vaultState.vaultPath;

  if (vaultPath === activeVaultPath) {
    return;
  }

  activeVaultPath = vaultPath;

  if (autoSyncTimer !== null) {
    window.clearTimeout(autoSyncTimer);
    autoSyncTimer = null;
  }

  setSyncState("status", "idle");
  setSyncState("offlineQueue", []);

  if (!vaultPath) {
    setSyncState("lastSyncTimestamp", null);
    return;
  }

  const lastSyncTimestamp = await getVaultSyncIDBValue<number>(LAST_SYNC_TIMESTAMP_KEY, vaultPath);
  setSyncState("lastSyncTimestamp", lastSyncTimestamp);
};

const scheduleAutoSync = () => {
  if (!vaultState.isPaired || !navigator.onLine) {
    return;
  }

  if (autoSyncTimer !== null) {
    window.clearTimeout(autoSyncTimer);
  }

  autoSyncTimer = window.setTimeout(() => {
    autoSyncTimer = null;
    void syncNow();
  }, AUTO_SYNC_DEBOUNCE_MS);
};

const setupDbChangeWatcher = () => {
  if (dbWatcherInitialized) {
    return;
  }

  createRoot(() => {
    let lastSeenVersion = dbVersion();

    createEffect(() => {
      const version = dbVersion();

      if (version === lastSeenVersion) {
        return;
      }

      lastSeenVersion = version;

      if (applyingRemoteSync || !vaultState.isPaired) {
        return;
      }

      scheduleAutoSync();
    });
  });

  dbWatcherInitialized = true;
};

const getLocalChanges = async (): Promise<SyncChangesPayload | null> => {
  const lastUploadedDbVersion = (await getVaultSyncIDBValue<number>(LAST_UPLOADED_DB_VERSION_KEY)) ?? 0;
  const rows = await query<{
    table: string;
    pk: unknown;
    cid: string;
    val: unknown;
    col_version: number;
    db_version: number;
    site_id: unknown;
    cl: number;
    seq: number;
  }>(
    `SELECT "table", "pk", "cid", "val", "col_version", "db_version",
            COALESCE("site_id", crsql_site_id()) AS "site_id",
            "cl", "seq"
       FROM "crsql_changes"
      WHERE "db_version" > ?
        AND ("site_id" = crsql_site_id() OR "site_id" IS NULL)
      ORDER BY "db_version" ASC, "seq" ASC`,
    [lastUploadedDbVersion],
  );

  if (rows.length === 0) {
    return null;
  }

  return {
    changes: rows.map((row) => ({
      table: row.table,
      pk: encodeSqliteValue(row.pk),
      cid: row.cid,
      val: encodeSqliteValue(row.val),
      col_version: row.col_version,
      db_version: row.db_version,
      site_id: encodeSqliteValue(row.site_id),
      cl: row.cl,
      seq: row.seq,
    })),
    maxDbVersion: rows[rows.length - 1]!.db_version,
  };
};

const uploadChanges = async (payload: SyncChangesPayload): Promise<number> => {
  if (!vaultState.vaultPath || !vaultState.deviceId || !vaultState.vaultKey) {
    throw new Error("Vault not configured for sync");
  }

  const cryptoKey = await importKey(vaultState.vaultKey);
  const encrypted = await encryptData(cryptoKey, encodeChangesPayload(payload));
  const response = await fetch(buildVaultApiPath(vaultState.vaultPath, "upload"), {
    method: "POST",
    headers: {
      "X-Device-Id": vaultState.deviceId,
    },
    body: encrypted.slice(0),
  });

  if (!response.ok) {
    throw new Error(`Upload failed: ${response.status}`);
  }

  const result = (await response.json()) as { timestamp: number };
  return result.timestamp;
};

const applyChanges = async (changes: SyncChangeRow[]) => {
  if (changes.length === 0) {
    return;
  }

  applyingRemoteSync = true;

  try {
    await exec("BEGIN");

    for (const change of changes) {
      await exec(
        `INSERT INTO "crsql_changes"
           ("table", "pk", "cid", "val", "col_version", "db_version", "site_id", "cl", "seq")
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          change.table,
          decodeSqliteValue(change.pk),
          change.cid,
          decodeSqliteValue(change.val),
          change.col_version,
          change.db_version,
          decodeSqliteValue(change.site_id),
          change.cl,
          change.seq,
        ],
      );
    }

    await exec("COMMIT");
  } catch (error) {
    try {
      await exec("ROLLBACK");
    } catch {
      // Nothing useful to do here.
    }
    throw error;
  } finally {
    applyingRemoteSync = false;
  }
};

const downloadAndApplyChangesAfter = async (afterTimestamp: number | null): Promise<number> => {
  if (!vaultState.vaultPath || !vaultState.vaultKey) {
    return 0;
  }

  const listUrl = new URL(buildVaultApiPath(vaultState.vaultPath, "list"), window.location.origin);

  if (afterTimestamp !== null) {
    listUrl.searchParams.set("after", String(afterTimestamp));
  }

  const response = await fetch(listUrl);
  if (!response.ok) {
    throw new Error(`Failed to list changesets: ${response.status}`);
  }

  const { changesets } = (await response.json()) as {
    changesets: Array<{ key: string; timestamp: number }>;
  };

  if (changesets.length === 0) {
    return 0;
  }

  const cryptoKey = await importKey(vaultState.vaultKey);
  let appliedCount = 0;

  for (const changeset of changesets) {
    const downloadResponse = await fetch(buildVaultApiPath(vaultState.vaultPath, "download", changeset.key));
    if (!downloadResponse.ok) {
      throw new Error(`Failed to download ${changeset.key}: ${downloadResponse.status}`);
    }

    const encrypted = new Uint8Array(await downloadResponse.arrayBuffer());
    const decrypted = await decryptData(cryptoKey, encrypted);
    const payload = decodeChangesPayload(decrypted);

    await applyChanges(payload.changes);
    await setVaultSyncIDBValue(LAST_REMOTE_TIMESTAMP_KEY, changeset.timestamp);
    await updateVisibleLastSync(changeset.timestamp);
    appliedCount += payload.changes.length;
  }

  return appliedCount;
};

const hasSyncableData = async () => {
  const workspaces = await query<{ count: number }>(
    "SELECT COUNT(*) as count FROM workspaces WHERE id != ?",
    [DEFAULT_WORKSPACE_ID],
  );
  const tasks = await query<{ count: number }>("SELECT COUNT(*) as count FROM tasks");

  return (workspaces[0]?.count ?? 0) > 0 || (tasks[0]?.count ?? 0) > 0;
};

const generateSnapshot = async (): Promise<Uint8Array | null> => {
  const workspaces = await query<SnapshotWorkspaceRow>(
    "SELECT id, name, created_at, updated_at FROM workspaces ORDER BY created_at ASC",
  );
  const tasks = await query<SnapshotTaskRow>(
    `SELECT id, parent_id, workspace_id, text, completed, created_at, updated_at, due_at, rank
       FROM tasks
      ORDER BY created_at ASC`,
  );

  if (workspaces.length === 0 && tasks.length === 0) {
    return null;
  }

  return encodeSnapshotPayload({ workspaces, tasks });
};

const uploadSnapshot = async (snapshot: Uint8Array): Promise<number> => {
  if (!vaultState.vaultPath || !vaultState.deviceId || !vaultState.vaultKey) {
    throw new Error("Vault not configured for sync");
  }

  const cryptoKey = await importKey(vaultState.vaultKey);
  const encrypted = await encryptData(cryptoKey, snapshot);
  const response = await fetch(buildVaultApiPath(vaultState.vaultPath, "snapshots", "upload"), {
    method: "POST",
    headers: {
      "X-Device-Id": vaultState.deviceId,
    },
    body: encrypted.slice(0),
  });

  if (!response.ok) {
    throw new Error(`Snapshot upload failed: ${response.status}`);
  }

  const result = (await response.json()) as { timestamp: number };
  return result.timestamp;
};

const createAndUploadSnapshot = async (): Promise<number | null> => {
  const snapshot = await generateSnapshot();
  if (!snapshot) {
    return null;
  }

  const timestamp = await uploadSnapshot(snapshot);
  await setVaultSyncIDBValue(LAST_SNAPSHOT_TIMESTAMP_KEY, timestamp);
  await setVaultSyncIDBValue(CHANGESETS_SINCE_SNAPSHOT_KEY, 0);
  await updateVisibleLastSync(timestamp);

  return timestamp;
};

const shouldCreateSnapshot = async (): Promise<boolean> => {
  const lastSnapshotTimestamp = await getVaultSyncIDBValue<number>(LAST_SNAPSHOT_TIMESTAMP_KEY);
  const changesetsSinceSnapshot = (await getVaultSyncIDBValue<number>(CHANGESETS_SINCE_SNAPSHOT_KEY)) ?? 0;

  if (!changesetsSinceSnapshot) {
    return false;
  }

  if (lastSnapshotTimestamp && Date.now() - lastSnapshotTimestamp < SNAPSHOT_INTERVAL_MS) {
    return false;
  }

  return true;
};

const shouldCreateSnapshotByThreshold = async (): Promise<boolean> => {
  const lastSnapshotTimestamp = await getVaultSyncIDBValue<number>(LAST_SNAPSHOT_TIMESTAMP_KEY);
  const changesetsSinceSnapshot = (await getVaultSyncIDBValue<number>(CHANGESETS_SINCE_SNAPSHOT_KEY)) ?? 0;

  if (lastSnapshotTimestamp && Date.now() - lastSnapshotTimestamp < SNAPSHOT_INTERVAL_MS) {
    return false;
  }

  return changesetsSinceSnapshot >= SNAPSHOT_CHANGESET_THRESHOLD;
};

export const incrementChangesetCounter = async (): Promise<void> => {
  const current = (await getVaultSyncIDBValue<number>(CHANGESETS_SINCE_SNAPSHOT_KEY)) ?? 0;
  await setVaultSyncIDBValue(CHANGESETS_SINCE_SNAPSHOT_KEY, current + 1);
};

const resetLocalStateForRemoteVault = async () => {
  applyingRemoteSync = true;

  try {
    await exec("BEGIN");
    await exec("DELETE FROM tasks");
    await exec("DELETE FROM workspaces");
    await exec(
      "INSERT INTO workspaces (id, name, created_at, updated_at) VALUES (?, ?, ?, ?)",
      [DEFAULT_WORKSPACE_ID, DEFAULT_WORKSPACE_NAME, Date.now(), Date.now()],
    );
    await exec("COMMIT");
  } catch (error) {
    try {
      await exec("ROLLBACK");
    } catch {
      // Nothing useful to do here.
    }
    throw error;
  } finally {
    applyingRemoteSync = false;
  }
};

const downloadLatestSnapshot = async (): Promise<{ snapshot: SyncSnapshotPayload; timestamp: number } | null> => {
  if (!vaultState.vaultPath || !vaultState.vaultKey) {
    return null;
  }

  const listUrl = new URL(buildVaultApiPath(vaultState.vaultPath, "snapshots", "list"), window.location.origin);

  const listResponse = await fetch(listUrl);
  if (!listResponse.ok) {
    throw new Error(`Failed to list snapshots: ${listResponse.status}`);
  }

  const { snapshots } = (await listResponse.json()) as {
    snapshots: Array<{ key: string; timestamp: number }>;
  };

  if (snapshots.length === 0) {
    return null;
  }

  const latestSnapshot = snapshots[snapshots.length - 1]!;
  const downloadResponse = await fetch(
    buildVaultApiPath(vaultState.vaultPath, "snapshots", "download", latestSnapshot.key),
  );
  if (!downloadResponse.ok) {
    throw new Error(`Failed to download snapshot ${latestSnapshot.key}: ${downloadResponse.status}`);
  }

  const cryptoKey = await importKey(vaultState.vaultKey);
  const encrypted = new Uint8Array(await downloadResponse.arrayBuffer());
  const decrypted = await decryptData(cryptoKey, encrypted);

  return {
    snapshot: decodeSnapshotPayload(decrypted),
    timestamp: latestSnapshot.timestamp,
  };
};

const applySnapshot = async (snapshot: SyncSnapshotPayload) => {
  applyingRemoteSync = true;

  try {
    await exec("BEGIN");
    await exec("DELETE FROM tasks");
    await exec("DELETE FROM workspaces");

    for (const workspace of snapshot.workspaces) {
      await exec(
        "INSERT INTO workspaces (id, name, created_at, updated_at) VALUES (?, ?, ?, ?)",
        [workspace.id, workspace.name, workspace.created_at, workspace.updated_at],
      );
    }

    for (const task of snapshot.tasks) {
      await exec(
        `INSERT INTO tasks
           (id, parent_id, workspace_id, text, completed, created_at, updated_at, due_at, rank)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          task.id,
          task.parent_id,
          task.workspace_id,
          task.text,
          task.completed,
          task.created_at,
          task.updated_at,
          task.due_at,
          task.rank,
        ],
      );
    }

    await exec("COMMIT");
  } catch (error) {
    try {
      await exec("ROLLBACK");
    } catch {
      // Nothing useful to do here.
    }
    throw error;
  } finally {
    applyingRemoteSync = false;
  }
};

const bootstrapRemoteState = async (): Promise<DownloadResult> => {
  if (!vaultState.requiresRemoteBootstrap) {
    const lastRemoteTimestamp = await getVaultSyncIDBValue<number>(LAST_REMOTE_TIMESTAMP_KEY);
    const downloadedChangesetCount = await downloadAndApplyChangesAfter(lastRemoteTimestamp);

    return {
      downloadedSnapshot: false,
      downloadedChangesetCount,
    };
  }

  await resetLocalStateForRemoteVault();

  const snapshotResult = await downloadLatestSnapshot();
  if (snapshotResult) {
    await applySnapshot(snapshotResult.snapshot);
    await setVaultSyncIDBValue(LAST_REMOTE_TIMESTAMP_KEY, snapshotResult.timestamp);
    await setVaultSyncIDBValue(LAST_SNAPSHOT_TIMESTAMP_KEY, snapshotResult.timestamp);
    await setVaultSyncIDBValue(CHANGESETS_SINCE_SNAPSHOT_KEY, 0);
    await updateVisibleLastSync(snapshotResult.timestamp);

    const downloadedChangesetCount = await downloadAndApplyChangesAfter(snapshotResult.timestamp - 1);
    return {
      downloadedSnapshot: true,
      downloadedChangesetCount,
    };
  }

  const downloadedChangesetCount = await downloadAndApplyChangesAfter(null);
  return {
    downloadedSnapshot: false,
    downloadedChangesetCount,
  };
};

const flushPersistedQueue = async () => {
  if (!vaultState.vaultPath) {
    return;
  }

  const queuedItems = await getSyncQueue(vaultState.vaultPath);
  for (const item of queuedItems) {
    try {
      const response = await fetch(buildVaultApiPath(item.vaultPath, "upload"), {
        method: "POST",
        headers: {
          "X-Device-Id": item.deviceId,
        },
        body: item.payload.slice(0),
      });

      if (!response.ok) {
        continue;
      }

      const result = (await response.json()) as { timestamp: number };
      await removeFromSyncQueue(item.id!);
      await setVaultSyncIDBValue(LAST_UPLOADED_DB_VERSION_KEY, item.maxDbVersion, item.vaultPath);
      await updateVisibleLastSync(result.timestamp);
      await incrementChangesetCounter();

      setSyncState(
        produce((draft) => {
          draft.offlineQueue = draft.offlineQueue.filter(
            (queued) => !(queued.vaultPath === item.vaultPath && queued.timestamp === item.timestamp),
          );
        }),
      );
    } catch (error) {
      console.error(`Queued upload retry failed for ${item.id}:`, error);
    }
  }
};

export const syncNow = async (): Promise<void> => {
  if (activeSyncPromise) {
    return activeSyncPromise;
  }

  activeSyncPromise = (async () => {
    if (!vaultState.isPaired || !vaultState.vaultPath || !vaultState.vaultKey || !vaultState.deviceId) {
      return;
    }

    await hydrateSyncStateForCurrentVault();
    setSyncState("status", "syncing");
    let syncFailed = false;

    try {
      const downloadResult = await bootstrapRemoteState();
      const existingSnapshotTimestamp = await getVaultSyncIDBValue<number>(LAST_SNAPSHOT_TIMESTAMP_KEY);
      const shouldUploadBootstrapSnapshot =
        existingSnapshotTimestamp === null
        && (
          !vaultState.requiresRemoteBootstrap
          || downloadResult.downloadedSnapshot
          || downloadResult.downloadedChangesetCount > 0
          || await hasSyncableData()
        );

      const localChanges = await getLocalChanges();
      if (localChanges) {
        try {
          const timestamp = await uploadChanges(localChanges);
          await setVaultSyncIDBValue(LAST_UPLOADED_DB_VERSION_KEY, localChanges.maxDbVersion);
          await updateVisibleLastSync(timestamp);
          await incrementChangesetCounter();

          if (await shouldCreateSnapshotByThreshold()) {
            await createAndUploadSnapshot();
          }
        } catch (error) {
          console.error("Upload failed, queuing for retry:", error);

          const cryptoKey = await importKey(vaultState.vaultKey);
          const encrypted = await encryptData(cryptoKey, encodeChangesPayload(localChanges));
          const queuedAt = Date.now();

          await addToSyncQueue({
            vaultPath: vaultState.vaultPath,
            deviceId: vaultState.deviceId,
            payload: encrypted,
            maxDbVersion: localChanges.maxDbVersion,
            timestamp: queuedAt,
          });
          await registerBackgroundSync();

          setSyncState(
            produce((draft) => {
              draft.offlineQueue.push({
                vaultPath: vaultState.vaultPath!,
                maxDbVersion: localChanges.maxDbVersion,
                timestamp: queuedAt,
              });
            }),
          );
        }
      }

      if (shouldUploadBootstrapSnapshot) {
        await createAndUploadSnapshot();
      }

      await flushPersistedQueue();

      if (vaultState.requiresRemoteBootstrap) {
        await resolveRemoteBootstrap();
      }
    } catch (error) {
      syncFailed = true;
      console.error("Sync error:", error);
      setSyncState("status", "error");
      throw error;
    } finally {
      if (!syncFailed) {
        setSyncState("status", "idle");
      }
    }
  })();

  try {
    await activeSyncPromise;
  } finally {
    activeSyncPromise = null;
  }
};

export const syncStateStore = syncState;

const setupVisibilityListener = () => {
  document.addEventListener("visibilitychange", async () => {
    if (document.visibilityState === "hidden") {
      if (!navigator.onLine) {
        wasOfflineWhileHidden = true;
      }

      if (!vaultState.isPaired) {
        return;
      }

      try {
        if (await shouldCreateSnapshot()) {
          await createAndUploadSnapshot();
        }
      } catch (error) {
        console.error("Failed to create snapshot on visibility change:", error);
      }

      return;
    }

    if (wasOfflineWhileHidden && navigator.onLine && vaultState.isPaired) {
      wasOfflineWhileHidden = false;
      void syncNow();
    }
  });
};

const setupOnlineListener = () => {
  window.addEventListener("online", () => {
    if (vaultState.isPaired) {
      void syncNow();
    }
  });
};

export const initializeSync = async () => {
  if (!vaultState.isPaired) {
    return;
  }

  if (!listenersInitialized) {
    setupDbChangeWatcher();
    setupVisibilityListener();
    setupOnlineListener();
    listenersInitialized = true;
  }

  await hydrateSyncStateForCurrentVault();
  await syncNow();
};

/* 1. Use a more-intuitive box-sizing model */
*, *::before, *::after {
  box-sizing: border-box;
}

/* 2. Remove default margin */
* {
  margin: 0;
}

/* 3. Enable keyword animations */
@media (prefers-reduced-motion: no-preference) {
  html {
    interpolate-size: allow-keywords;
  }
}

body {
  /* 4. Add accessible line-height */
  line-height: 1.5;
  /* 5. Improve text rendering */
  -webkit-font-smoothing: antialiased;
}

/* 6. Improve media defaults */
img, picture, video, canvas, svg {
  display: block;
  max-width: 100%;
}

/* 7. Inherit fonts for form controls */
input, button, textarea, select {
  font: inherit;
}

/* 8. Avoid text overflows */
p, h1, h2, h3, h4, h5, h6 {
  overflow-wrap: break-word;
}

/* 9. Improve line wrapping */
p {
  text-wrap: pretty;
}
h1, h2, h3, h4, h5, h6 {
  text-wrap: balance;
}

/*
  10. Create a root stacking context
*/
#root, #__next {
  isolation: isolate;
}

import { type APIEvent } from "@solidjs/start/server";
import { readFile } from "node:fs/promises";
import { resolveVaultFilePath } from "../../_storage";
import { enforceSyncRateLimit } from "../../_security";

export async function GET(event: APIEvent) {
  const rateLimitResponse = enforceSyncRateLimit(event.request, event.clientAddress, "read");
  if (rateLimitResponse) {
    return rateLimitResponse;
  }

  const vault = event.params.vault;
  const filename = event.params.filename;

  if (!vault || !filename) {
    return new Response("Missing vault or filename", { status: 400 });
  }

  if (!filename.endsWith(".bin")) {
    return new Response("Invalid filename format", { status: 400 });
  }

  const filePath = resolveVaultFilePath(vault, filename);
  if (!filePath) {
    return new Response("Invalid vault path", { status: 400 });
  }

  try {
    const data = await readFile(filePath);
    return new Response(data, {
      headers: { "content-type": "application/octet-stream" },
    });
  } catch {
    return new Response("Not found", { status: 404 });
  }
}

import { type APIEvent } from "@solidjs/start/server";
import { readdir } from "node:fs/promises";
import { resolveVaultPath } from "../_storage";
import { enforceSyncRateLimit } from "../_security";

export async function GET(event: APIEvent) {
  const rateLimitResponse = enforceSyncRateLimit(event.request, event.clientAddress, "read");
  if (rateLimitResponse) {
    return rateLimitResponse;
  }

  const vault = event.params.vault;
  const vaultDir = resolveVaultPath(vault);
  const afterParam = new URL(event.request.url).searchParams.get("after");

  if (!vaultDir) {
    return new Response("Invalid vault path", { status: 400 });
  }

  const after = afterParam ? Number.parseInt(afterParam, 10) : null;

  let files: string[];
  try {
    files = await readdir(vaultDir);
  } catch {
    return Response.json({ changesets: [] });
  }

  const changesets = files
    .filter((filename) => filename.endsWith(".bin"))
    .map((filename) => ({
      key: filename,
      timestamp: Number.parseInt(filename.split("-")[0] ?? "", 10),
    }))
    .filter((entry) => !Number.isNaN(entry.timestamp))
    .filter((entry) => (after === null ? true : entry.timestamp > after))
    .sort((left, right) => left.timestamp - right.timestamp);

  return Response.json({ changesets });
}

