import { describe, expect, it } from "vitest";
import { resolveVaultFilePath, resolveVaultPath, STORAGE_ROOT } from "../_storage";

describe("sync storage path resolution", () => {
  it("keeps valid vaults inside the storage root", () => {
    const resolved = resolveVaultPath("tenant-a/vault-01");

    expect(resolved).toBe(`${STORAGE_ROOT}/tenant-a/vault-01`);
  });

  it.each([
    "",
    ".",
    "..",
    "../vault",
    "vault/..",
    "vault//nested",
    "vault\\nested",
    "%2e%2e",
    "vault/%2e%2e",
    "vault%2Fnested",
    "%2fetc",
  ])("rejects unsafe vault path %s", (vault) => {
    expect(resolveVaultPath(vault)).toBeNull();
  });

  it.each([
    "..",
    "../escape.bin",
    "%2e%2e",
    "nested/file.bin",
    "nested\\file.bin",
    "%2fescape.bin",
  ])("rejects unsafe file segment %s", (filename) => {
    expect(resolveVaultFilePath("safe-vault", filename)).toBeNull();
  });
});

import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { mkdir, writeFile, readFile, readdir, rm } from "node:fs/promises";
import { join, resolve } from "node:path";
import { POST } from "../[vault]/upload";
import { GET as listGET } from "../[vault]/list";
import { GET as downloadGET } from "../[vault]/download/[filename]";
import {
  CHANGESET_UPLOAD_MAX_BYTES,
  MAX_CHANGESETS_PER_VAULT,
} from "../_security";
import { resetRateLimitStore } from "~/lib/requestSecurity";

const STORAGE_ROOT = resolve("./storage/vaults");
const TEST_VAULT = "test-vault-abc123";
const TEST_DEVICE = "device-001";

function makeRequest(url: string, init?: RequestInit): Request {
  return new Request(new URL(url, "http://localhost:3000"), init);
}

function makeAPIEvent(request: Request, params: Record<string, string> = {}) {
  return { request, params } as any;
}

describe("Sync API Endpoints", () => {
  beforeEach(async () => {
    resetRateLimitStore();
    await rm(join(STORAGE_ROOT, TEST_VAULT), { recursive: true, force: true });
  });

  afterEach(async () => {
    resetRateLimitStore();
    await rm(join(STORAGE_ROOT, TEST_VAULT), { recursive: true, force: true });
  });

  describe("POST /api/sync/:vault/upload", () => {
    it("stores uploaded blob and returns key + timestamp", async () => {
      const body = new Uint8Array([1, 2, 3, 4, 5]);
      const request = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": TEST_DEVICE,
        },
        body: body,
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(200);

      const json = await response.json();
      expect(json.key).not.toContain(TEST_VAULT);
      expect(json.key).toContain(TEST_DEVICE);
      expect(json.key).toMatch(/\.bin$/);
      expect(typeof json.timestamp).toBe("number");

      // Verify file exists on disk
      const files = await readdir(join(STORAGE_ROOT, TEST_VAULT));
      expect(files.length).toBe(1);
      expect(files[0]).toMatch(/\.bin$/);

      const fileData = await readFile(join(STORAGE_ROOT, TEST_VAULT, files[0]));
      expect(new Uint8Array(fileData)).toEqual(body);
    });

    it("returns 400 when missing headers", async () => {
      const request = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
        method: "POST",
        body: new Uint8Array([1]),
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(400);
    });

    it("rejects oversized uploads with 413", async () => {
      const body = new Uint8Array(CHANGESET_UPLOAD_MAX_BYTES + 1);
      const request = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": TEST_DEVICE,
          "content-length": String(body.byteLength),
        },
        body,
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));

      expect(response.status).toBe(413);
    });

    it("rate limits repeated writes and recovers after the window resets", async () => {
      vi.useFakeTimers();
      vi.setSystemTime(new Date("2025-01-01T00:00:00Z"));

      try {
        for (let attempt = 0; attempt < 30; attempt += 1) {
          const request = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
            method: "POST",
            headers: {
              "X-Device-Id": TEST_DEVICE,
              "user-agent": "vitest",
              "x-forwarded-for": "198.51.100.10",
            },
            body: new Uint8Array([attempt]),
          });

          const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
          expect(response.status).toBe(200);
          vi.advanceTimersByTime(1);
        }

        const limitedRequest = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
          method: "POST",
          headers: {
            "X-Device-Id": TEST_DEVICE,
            "user-agent": "vitest",
            "x-forwarded-for": "198.51.100.10",
          },
          body: new Uint8Array([31]),
        });

        const limitedResponse = await POST(makeAPIEvent(limitedRequest, { vault: TEST_VAULT }));
        expect(limitedResponse.status).toBe(429);

        vi.advanceTimersByTime(60_001);

        const recoveredRequest = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
          method: "POST",
          headers: {
            "X-Device-Id": TEST_DEVICE,
            "user-agent": "vitest",
            "x-forwarded-for": "198.51.100.10",
          },
          body: new Uint8Array([32]),
        });

        const recoveredResponse = await POST(makeAPIEvent(recoveredRequest, { vault: TEST_VAULT }));
        expect(recoveredResponse.status).toBe(200);
      } finally {
        vi.useRealTimers();
      }
    });

    it("prunes the oldest changesets once the vault exceeds the configured limit", async () => {
      const vaultDir = join(STORAGE_ROOT, TEST_VAULT);
      await mkdir(vaultDir, { recursive: true });

      for (let index = 1; index <= MAX_CHANGESETS_PER_VAULT; index += 1) {
        await writeFile(join(vaultDir, `${index}-${TEST_DEVICE}.bin`), Buffer.from([index % 255]));
      }

      const request = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": TEST_DEVICE,
        },
        body: new Uint8Array([9, 9, 9]),
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(200);

      const files = (await readdir(vaultDir)).filter((filename) => filename.endsWith(".bin"));
      expect(files).toHaveLength(MAX_CHANGESETS_PER_VAULT);
      expect(files).not.toContain(`1-${TEST_DEVICE}.bin`);
    });
  });

  describe("GET /api/sync/:vault/list", () => {
    it("returns changesets for a vault", async () => {
      // Create test files
      const vaultDir = join(STORAGE_ROOT, TEST_VAULT);
      await mkdir(vaultDir, { recursive: true });
      await writeFile(join(vaultDir, "1000-device1.bin"), Buffer.from([1]));
      await writeFile(join(vaultDir, "2000-device1.bin"), Buffer.from([2]));

      const request = makeRequest(`/api/sync/${TEST_VAULT}/list`);
      const response = await listGET(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(200);

      const json = await response.json();
      expect(json.changesets).toHaveLength(2);
      expect(json.changesets[0].timestamp).toBe(1000);
      expect(json.changesets[1].timestamp).toBe(2000);
      expect(json.changesets[0].key).toBe("1000-device1.bin");
    });

    it("filters changesets with after parameter", async () => {
      const vaultDir = join(STORAGE_ROOT, TEST_VAULT);
      await mkdir(vaultDir, { recursive: true });
      await writeFile(join(vaultDir, "1000-device1.bin"), Buffer.from([1]));
      await writeFile(join(vaultDir, "2000-device1.bin"), Buffer.from([2]));
      await writeFile(join(vaultDir, "3000-device1.bin"), Buffer.from([3]));

      const request = makeRequest(`/api/sync/${TEST_VAULT}/list?after=1000`);
      const response = await listGET(makeAPIEvent(request, { vault: TEST_VAULT }));
      const json = await response.json();

      expect(json.changesets).toHaveLength(2);
      expect(json.changesets[0].timestamp).toBe(2000);
      expect(json.changesets[1].timestamp).toBe(3000);
    });

    it("returns empty array for nonexistent vault", async () => {
      const request = makeRequest("/api/sync/nonexistent-vault/list");
      const response = await listGET(makeAPIEvent(request, { vault: "nonexistent-vault" }));
      const json = await response.json();

      expect(json.changesets).toEqual([]);
    });
  });

  describe("GET /api/sync/:vault/download/:filename", () => {
    it("returns the encrypted blob", async () => {
      const vaultDir = join(STORAGE_ROOT, TEST_VAULT);
      await mkdir(vaultDir, { recursive: true });
      const blob = Buffer.from([10, 20, 30, 40, 50]);
      await writeFile(join(vaultDir, "1000-device1.bin"), blob);

      const filename = "1000-device1.bin";
      const request = makeRequest(`/api/sync/${TEST_VAULT}/download/${filename}`);
      const response = await downloadGET(makeAPIEvent(request, { vault: TEST_VAULT, filename }));

      expect(response.status).toBe(200);
      expect(response.headers.get("content-type")).toBe(
        "application/octet-stream"
      );

      const data = new Uint8Array(await response.arrayBuffer());
      expect(data).toEqual(new Uint8Array(blob));
    });

    it("returns 404 for nonexistent key", async () => {
      const filename = "9999-nodevice.bin";
      const request = makeRequest(`/api/sync/${TEST_VAULT}/download/${filename}`);
      const response = await downloadGET(makeAPIEvent(request, { vault: TEST_VAULT, filename }));
      expect(response.status).toBe(404);
    });
  });

  describe("Full sync cycle", () => {
    it("upload → list → download returns same data", async () => {
      const originalData = new Uint8Array([99, 88, 77, 66, 55]);

      // Upload
      const uploadReq = makeRequest(`/api/sync/${TEST_VAULT}/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": "device-A",
        },
        body: originalData,
      });
      const uploadRes = await POST(makeAPIEvent(uploadReq, { vault: TEST_VAULT }));
      const { key, timestamp } = await uploadRes.json();

      // List
      const listReq = makeRequest(`/api/sync/${TEST_VAULT}/list`);
      const listRes = await listGET(makeAPIEvent(listReq, { vault: TEST_VAULT }));
      const { changesets } = await listRes.json();

      expect(changesets).toHaveLength(1);
      expect(changesets[0].key).toBe(key);
      expect(changesets[0].timestamp).toBe(timestamp);

      // Download
      const dlReq = makeRequest(`/api/sync/${TEST_VAULT}/download/${key}`);
      const dlRes = await downloadGET(makeAPIEvent(dlReq, { vault: TEST_VAULT, filename: key }));
      const downloaded = new Uint8Array(await dlRes.arrayBuffer());

      expect(downloaded).toEqual(originalData);
    });
  });
});

import { readdir, rm, stat } from "node:fs/promises";
import { join } from "node:path";
import {
  buildRateLimitBucketKey,
  consumeRateLimit,
  createRateLimitResponse,
  type RateLimitPolicy,
} from "~/lib/requestSecurity";

type StoredFile = {
  filename: string;
  path: string;
  size: number;
  timestamp: number;
};

type BodyReadResult =
  | {
      ok: true;
      body: Uint8Array;
    }
  | {
      ok: false;
      response: Response;
    };

export const CHANGESET_UPLOAD_MAX_BYTES = 256 * 1024;
export const SNAPSHOT_UPLOAD_MAX_BYTES = 5 * 1024 * 1024;
export const MAX_CHANGESETS_PER_VAULT = 200;
export const MAX_CHANGESET_BYTES_PER_VAULT = 8 * 1024 * 1024;
export const MAX_SNAPSHOTS_PER_VAULT = 5;

const SYNC_READ_POLICIES: readonly RateLimitPolicy[] = [
  {
    id: "sync-read-1m",
    maxRequests: 120,
    windowMs: 60_000,
  },
];

const SYNC_WRITE_POLICIES: readonly RateLimitPolicy[] = [
  {
    id: "sync-write-1m",
    maxRequests: 30,
    windowMs: 60_000,
  },
];

const PAYLOAD_TOO_LARGE_RESPONSE = (limit: number) =>
  new Response(`Payload too large. Limit is ${limit} bytes.`, { status: 413 });

const parseTimestamp = (filename: string) => {
  return Number.parseInt(filename.split("-")[0] ?? "", 10);
};

const compareStoredFiles = (left: StoredFile, right: StoredFile) => {
  if (left.timestamp !== right.timestamp) {
    return left.timestamp - right.timestamp;
  }

  return left.filename.localeCompare(right.filename);
};

const listStoredFiles = async (
  directory: string,
  isMatch: (filename: string) => boolean,
): Promise<StoredFile[]> => {
  let entries;

  try {
    entries = await readdir(directory, { withFileTypes: true });
  } catch {
    return [];
  }

  const files = await Promise.all(
    entries
      .filter((entry) => entry.isFile())
      .map(async (entry) => {
        if (!isMatch(entry.name)) {
          return null;
        }

        const timestamp = parseTimestamp(entry.name);
        if (Number.isNaN(timestamp)) {
          return null;
        }

        const path = join(directory, entry.name);
        const metadata = await stat(path);

        return {
          filename: entry.name,
          path,
          size: metadata.size,
          timestamp,
        } satisfies StoredFile;
      }),
  );

  return files.filter((file): file is StoredFile => file !== null).sort(compareStoredFiles);
};

const listChangesets = (vaultDir: string) =>
  listStoredFiles(vaultDir, (filename) => filename.endsWith(".bin") && !filename.endsWith(".snapshot.bin"));

const listSnapshots = (snapshotDir: string) =>
  listStoredFiles(snapshotDir, (filename) => filename.endsWith(".snapshot.bin"));

export const enforceSyncRateLimit = (
  request: Request,
  clientAddress: string | undefined,
  routeFamily: "read" | "write",
) => {
  const bucketKey = buildRateLimitBucketKey(request, `sync-${routeFamily}`, clientAddress);
  const result = consumeRateLimit(
    bucketKey,
    routeFamily === "write" ? SYNC_WRITE_POLICIES : SYNC_READ_POLICIES,
  );

  if (result.allowed) {
    return null;
  }

  return createRateLimitResponse("Too many sync requests. Please retry shortly.", result.retryAfterMs);
};

export const readRequestBodyWithinLimit = async (
  request: Request,
  maxBytes: number,
): Promise<BodyReadResult> => {
  const contentLengthHeader = request.headers.get("content-length");
  if (contentLengthHeader) {
    const contentLength = Number.parseInt(contentLengthHeader, 10);
    if (!Number.isNaN(contentLength) && contentLength > maxBytes) {
      return {
        ok: false,
        response: PAYLOAD_TOO_LARGE_RESPONSE(maxBytes),
      };
    }
  }

  if (!request.body) {
    return {
      ok: true,
      body: new Uint8Array(),
    };
  }

  const reader = request.body.getReader();
  const chunks: Uint8Array[] = [];
  let totalBytes = 0;

  while (true) {
    const { done, value } = await reader.read();
    if (done) {
      break;
    }

    totalBytes += value.byteLength;
    if (totalBytes > maxBytes) {
      await reader.cancel();
      return {
        ok: false,
        response: PAYLOAD_TOO_LARGE_RESPONSE(maxBytes),
      };
    }

    chunks.push(value);
  }

  const body = new Uint8Array(totalBytes);
  let offset = 0;

  for (const chunk of chunks) {
    body.set(chunk, offset);
    offset += chunk.byteLength;
  }

  return {
    ok: true,
    body,
  };
};

export const pruneVaultChangesets = async (vaultDir: string) => {
  const changesets = await listChangesets(vaultDir);
  let totalBytes = changesets.reduce((sum, entry) => sum + entry.size, 0);

  while (changesets.length > MAX_CHANGESETS_PER_VAULT || totalBytes > MAX_CHANGESET_BYTES_PER_VAULT) {
    const oldest = changesets.shift();
    if (!oldest) {
      break;
    }

    totalBytes -= oldest.size;
    await rm(oldest.path, { force: true });
  }
};

export const pruneVaultAfterSnapshot = async (vaultDir: string, snapshotTimestamp: number) => {
  const changesets = await listChangesets(vaultDir);
  for (const entry of changesets) {
    if (entry.timestamp < snapshotTimestamp) {
      await rm(entry.path, { force: true });
    }
  }

  const snapshotDir = join(vaultDir, "snapshots");
  const snapshots = await listSnapshots(snapshotDir);
  const staleSnapshots = Math.max(snapshots.length - MAX_SNAPSHOTS_PER_VAULT, 0);

  for (const entry of snapshots.slice(0, staleSnapshots)) {
    await rm(entry.path, { force: true });
  }

  await pruneVaultChangesets(vaultDir);
};

import { isAbsolute, relative, resolve } from "node:path";

export const STORAGE_ROOT = resolve("./storage/vaults");

const isSinglePathSegment = (value: string) => {
  if (!value || value === "." || value === ".." || value.includes("/") || value.includes("\\")) {
    return false;
  }

  let decoded: string;
  try {
    decoded = decodeURIComponent(value);
  } catch {
    return false;
  }

  return decoded.length > 0
    && decoded !== "."
    && decoded !== ".."
    && !decoded.includes("/")
    && !decoded.includes("\\");
};

const isWithinStorageRoot = (candidate: string) => {
  const resolvedCandidate = resolve(candidate);
  const relativePath = relative(STORAGE_ROOT, resolvedCandidate);

  return !relativePath.startsWith("..") && !isAbsolute(relativePath);
};

const splitVaultSegments = (vault: string | undefined) => {
  if (!vault) {
    return null;
  }

  const segments = vault.split("/");
  if (segments.some((segment) => !isSinglePathSegment(segment))) {
    return null;
  }

  return segments;
};

export const resolveVaultPath = (vault: string | undefined) => {
  const segments = splitVaultSegments(vault);
  if (!segments) {
    return null;
  }

  const vaultDir = resolve(STORAGE_ROOT, ...segments);
  if (!isWithinStorageRoot(vaultDir)) {
    return null;
  }

  return vaultDir;
};

export const resolveVaultFilePath = (vault: string | undefined, ...segments: string[]) => {
  const vaultSegments = splitVaultSegments(vault);
  if (!vaultSegments) {
    return null;
  }

  if (segments.some((segment) => !isSinglePathSegment(segment))) {
    return null;
  }

  const filePath = resolve(STORAGE_ROOT, ...vaultSegments, ...segments);
  if (!isWithinStorageRoot(filePath)) {
    return null;
  }

  return filePath;
};

import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { mkdir, writeFile, readFile, readdir, rm } from "node:fs/promises";
import { join, resolve } from "node:path";
import { POST } from "../../[vault]/snapshots/upload";
import { GET as listGET } from "../../[vault]/snapshots/list";
import { GET as downloadGET } from "../../[vault]/snapshots/download/[filename]";
import {
  MAX_SNAPSHOTS_PER_VAULT,
  SNAPSHOT_UPLOAD_MAX_BYTES,
} from "../../_security";
import { resetRateLimitStore } from "~/lib/requestSecurity";

const STORAGE_ROOT = resolve("./storage/vaults");
const TEST_VAULT = "test-vault-snapshots";
const TEST_DEVICE = "device-snap-001";

function makeRequest(url: string, init?: RequestInit): Request {
  return new Request(new URL(url, "http://localhost:3000"), init);
}

function makeAPIEvent(request: Request, params: Record<string, string> = {}) {
  return { request, params } as any;
}

describe("Snapshot API Endpoints", () => {
  beforeEach(async () => {
    resetRateLimitStore();
    await rm(join(STORAGE_ROOT, TEST_VAULT), { recursive: true, force: true });
  });

  afterEach(async () => {
    resetRateLimitStore();
    await rm(join(STORAGE_ROOT, TEST_VAULT), { recursive: true, force: true });
  });

  describe("POST /api/sync/:vault/snapshots/upload", () => {
    it("stores snapshot and returns key + timestamp", async () => {
      const body = new Uint8Array([10, 20, 30, 40, 50]);
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": TEST_DEVICE,
        },
        body: body,
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(200);

      const json = await response.json();
      expect(json.key).not.toContain(TEST_VAULT);
      expect(json.key).toMatch(/\.snapshot\.bin$/);
      expect(typeof json.timestamp).toBe("number");

      const files = await readdir(join(STORAGE_ROOT, TEST_VAULT, "snapshots"));
      expect(files.length).toBe(1);
      expect(files[0]).toMatch(/\.snapshot\.bin$/);

      const fileData = await readFile(
        join(STORAGE_ROOT, TEST_VAULT, "snapshots", files[0])
      );
      expect(new Uint8Array(fileData)).toEqual(body);
    });

    it("returns 400 when missing headers", async () => {
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/upload`, {
        method: "POST",
        body: new Uint8Array([1]),
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(400);
    });

    it("rejects oversized snapshots with 413", async () => {
      const body = new Uint8Array(SNAPSHOT_UPLOAD_MAX_BYTES + 1);
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": TEST_DEVICE,
          "content-length": String(body.byteLength),
        },
        body,
      });

      const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));

      expect(response.status).toBe(413);
    });

    it("uses a new snapshot as the compaction point and trims stale snapshots", async () => {
      vi.useFakeTimers();
      vi.setSystemTime(new Date(6_000));

      try {
        const vaultDir = join(STORAGE_ROOT, TEST_VAULT);
        const snapshotDir = join(vaultDir, "snapshots");
        await mkdir(snapshotDir, { recursive: true });

        await writeFile(join(vaultDir, "1000-device-a.bin"), Buffer.from([1]));
        await writeFile(join(vaultDir, "2000-device-a.bin"), Buffer.from([2]));
        await writeFile(join(vaultDir, "7000-device-a.bin"), Buffer.from([7]));

        for (let timestamp = 1000; timestamp <= 5000; timestamp += 1000) {
          await writeFile(
            join(snapshotDir, `${timestamp}-${TEST_DEVICE}.snapshot.bin`),
            Buffer.from([timestamp / 1000]),
          );
        }

        const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/upload`, {
          method: "POST",
          headers: {
            "X-Device-Id": TEST_DEVICE,
          },
          body: new Uint8Array([9, 8, 7]),
        });

        const response = await POST(makeAPIEvent(request, { vault: TEST_VAULT }));
        expect(response.status).toBe(200);

        const remainingChangesets = (await readdir(vaultDir))
          .filter((filename) => filename.endsWith(".bin") && !filename.endsWith(".snapshot.bin"))
          .sort();
        expect(remainingChangesets).toEqual(["7000-device-a.bin"]);

        const remainingSnapshots = (await readdir(snapshotDir)).sort();
        expect(remainingSnapshots).toHaveLength(MAX_SNAPSHOTS_PER_VAULT);
        expect(remainingSnapshots).not.toContain(`1000-${TEST_DEVICE}.snapshot.bin`);
        expect(remainingSnapshots).toContain(`6000-${TEST_DEVICE}.snapshot.bin`);
      } finally {
        vi.useRealTimers();
      }
    });
  });

  describe("GET /api/sync/:vault/snapshots/list", () => {
    it("returns snapshots for a vault", async () => {
      const snapshotDir = join(STORAGE_ROOT, TEST_VAULT, "snapshots");
      await mkdir(snapshotDir, { recursive: true });
      await writeFile(
        join(snapshotDir, "1000-device1.snapshot.bin"),
        Buffer.from([1])
      );
      await writeFile(
        join(snapshotDir, "2000-device1.snapshot.bin"),
        Buffer.from([2])
      );

      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/list`);
      const response = await listGET(makeAPIEvent(request, { vault: TEST_VAULT }));
      expect(response.status).toBe(200);

      const json = await response.json();
      expect(json.snapshots).toHaveLength(2);
      expect(json.snapshots[0].timestamp).toBe(1000);
      expect(json.snapshots[1].timestamp).toBe(2000);
      expect(json.snapshots[0].key).toBe(
        "1000-device1.snapshot.bin"
      );
    });

    it("ignores non-snapshot files", async () => {
      const snapshotDir = join(STORAGE_ROOT, TEST_VAULT, "snapshots");
      await mkdir(snapshotDir, { recursive: true });
      await writeFile(
        join(snapshotDir, "1000-device1.snapshot.bin"),
        Buffer.from([1])
      );
      await writeFile(
        join(snapshotDir, "2000-device1.bin"),
        Buffer.from([2])
      );

      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/list`);
      const response = await listGET(makeAPIEvent(request, { vault: TEST_VAULT }));
      const json = await response.json();

      expect(json.snapshots).toHaveLength(1);
      expect(json.snapshots[0].timestamp).toBe(1000);
    });

    it("returns empty array for nonexistent vault", async () => {
      const request = makeRequest("/api/sync/nonexistent-vault/snapshots/list");
      const response = await listGET(makeAPIEvent(request, { vault: "nonexistent-vault" }));
      const json = await response.json();

      expect(json.snapshots).toEqual([]);
    });
  });

  describe("GET /api/sync/:vault/snapshots/download/:filename", () => {
    it("returns the snapshot blob", async () => {
      const snapshotDir = join(STORAGE_ROOT, TEST_VAULT, "snapshots");
      await mkdir(snapshotDir, { recursive: true });
      const blob = Buffer.from([10, 20, 30, 40, 50]);
      await writeFile(join(snapshotDir, "1000-device1.snapshot.bin"), blob);

      const filename = "1000-device1.snapshot.bin";
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/download/${filename}`);
      const response = await downloadGET(makeAPIEvent(request, { vault: TEST_VAULT, filename }));

      expect(response.status).toBe(200);
      expect(response.headers.get("content-type")).toBe(
        "application/octet-stream"
      );

      const data = new Uint8Array(await response.arrayBuffer());
      expect(data).toEqual(new Uint8Array(blob));
    });

    it("returns 404 for nonexistent snapshot", async () => {
      const filename = "9999-nodevice.snapshot.bin";
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/download/${filename}`);
      const response = await downloadGET(makeAPIEvent(request, { vault: TEST_VAULT, filename }));
      expect(response.status).toBe(404);
    });

    it("rejects non-.snapshot.bin keys", async () => {
      const filename = "1000-device1.bin";
      const request = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/download/${filename}`);
      const response = await downloadGET(makeAPIEvent(request, { vault: TEST_VAULT, filename }));
      expect(response.status).toBe(400);
    });
  });

  describe("Full snapshot cycle", () => {
    it("upload → list → download returns same data", async () => {
      const originalData = new Uint8Array([99, 88, 77, 66, 55]);

      // Upload
      const uploadReq = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/upload`, {
        method: "POST",
        headers: {
          "X-Device-Id": "device-A",
        },
        body: originalData,
      });
      const uploadRes = await POST(makeAPIEvent(uploadReq, { vault: TEST_VAULT }));
      const { key, timestamp } = await uploadRes.json();

      // List
      const listReq = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/list`);
      const listRes = await listGET(makeAPIEvent(listReq, { vault: TEST_VAULT }));
      const { snapshots } = await listRes.json();

      expect(snapshots).toHaveLength(1);
      expect(snapshots[0].key).toBe(key);
      expect(snapshots[0].timestamp).toBe(timestamp);

      // Download
      const dlReq = makeRequest(`/api/sync/${TEST_VAULT}/snapshots/download/${key}`);
      const dlRes = await downloadGET(makeAPIEvent(dlReq, { vault: TEST_VAULT, filename: key }));
      const downloaded = new Uint8Array(await dlRes.arrayBuffer());

      expect(downloaded).toEqual(originalData);
    });
  });
});

import { createMemo, createSignal, For, Show } from "solid-js";
import { A } from "@solidjs/router";
import { Title } from "@solidjs/meta";
import Filter from "lucide-solid/icons/filter";
import ArrowDownWideNarrow from "lucide-solid/icons/arrow-down-wide-narrow";
import Settings2 from "lucide-solid/icons/settings-2";
import TaskPrompt from "~/components/TaskPrompt";
import TasksList from "~/components/TasksList";
import {
  DEFAULT_LIST_FILTER,
  DEFAULT_LIST_SORT_MODE,
  listFilter,
  LIST_FILTER_OPTIONS,
  LIST_SORT_MODE_OPTIONS,
  listSortMode,
  setListFilter,
  setListSortMode,
  type ListFilter,
  type ListSortMode,
} from "~/stores/preferencesStore";
import {
  selectedWorkspaceId,
  selectWorkspace,
  tasks,
  workspaces,
  type TreeNode,
} from "~/stores/taskStore";

const FILTER_LABELS: Record<ListFilter, string> = {
  all: "All",
  active: "Active",
  completed: "Completed",
  stalled: "Stalled",
};

const SORT_LABELS: Record<ListSortMode, string> = {
  manual: "Manual",
  "due-date": "Due date",
};

const dueDateComparator = (a: TreeNode, b: TreeNode) => {
  const aDue = a.effectiveDueDate ?? Number.POSITIVE_INFINITY;
  const bDue = b.effectiveDueDate ?? Number.POSITIVE_INFINITY;

  if (aDue !== bDue) {
    return aDue - bDue;
  }

  return a.rank.localeCompare(b.rank);
};

const matchesFilter = (task: TreeNode, filterMode: ListFilter) => {
  if (filterMode === "all") {
    return true;
  }

  if (filterMode === "active") {
    return !task.completed;
  }

  if (filterMode === "completed") {
    return task.completed;
  }

  return task.isStalled && !task.completed;
};

const resolveEffectiveDueDate = (task: TreeNode, children: TreeNode[]) => {
  const earliestChildDueDate = children.reduce<number | null>((earliest, child) => {
    if (child.effectiveDueDate === null) {
      return earliest;
    }

    if (earliest === null || child.effectiveDueDate < earliest) {
      return child.effectiveDueDate;
    }

    return earliest;
  }, null);

  if (task.dueAt === null) {
    return earliestChildDueDate;
  }

  if (earliestChildDueDate === null) {
    return task.dueAt;
  }

  return Math.min(task.dueAt, earliestChildDueDate);
};

const projectVisibleTasks = (nodes: TreeNode[], filterMode: ListFilter): TreeNode[] =>
  nodes.flatMap((node) => {
    const children = projectVisibleTasks(node.children, filterMode);
    const effectiveDueDate = resolveEffectiveDueDate(node, children);

    // Keep matching descendants attached to their parent so the tree stays legible.
    if (!matchesFilter(node, filterMode) && children.length === 0) {
      return [];
    }

    return [{ ...node, children, effectiveDueDate }];
  });

const sortTasksByDueDate = (nodes: TreeNode[]): TreeNode[] =>
  nodes
    .map((node) => ({
      ...node,
      children: sortTasksByDueDate(node.children),
    }))
    .sort(dueDateComparator);

export default function Home() {
  const [activePanel, setActivePanel] = createSignal<"filter" | "sort" | null>(null);
  const [fabVisible, setFabVisible] = createSignal(true);

  let lastScrollY = 0;

  const visibleTasks = createMemo(() => {
    const projected = projectVisibleTasks(tasks(), listFilter());

    if (listSortMode() === "manual") {
      return projected;
    }

    return sortTasksByDueDate(projected);
  });

  const emptyStateMessage = createMemo(() => {
    if (listFilter() === "active") {
      return "No active tasks in this workspace.";
    }

    if (listFilter() === "completed") {
      return "No completed tasks in this workspace.";
    }

    if (listFilter() === "stalled") {
      return "No stalled tasks in this workspace.";
    }

    return "No tasks in this workspace yet.";
  });

  const handleScroll = (event: Event) => {
    const target = event.target as HTMLElement;
    const currentScrollY = target.scrollTop;

    if (currentScrollY > lastScrollY && currentScrollY > 50) {
      setFabVisible(false);
    } else {
      setFabVisible(true);
    }

    lastScrollY = currentScrollY;
  };

  const togglePanel = (panel: "filter" | "sort") => {
    setActivePanel(activePanel() === panel ? null : panel);
  };

  const applyFilter = (value: ListFilter) => {
    setListFilter(value);
    setActivePanel(null);
  };

  const applySort = (value: ListSortMode) => {
    setListSortMode(value);
    setActivePanel(null);
  };

  return (
    <div class="h-screen flex flex-col overflow-hidden bg-[#F9F9F8] text-stone-700 selection:bg-stone-200">
      <Title>FocusFlow</Title>

      <header class="flex-none px-6 py-5 flex justify-between items-center bg-[#F9F9F8]/90 backdrop-blur z-40 sticky top-0">
        <button
          type="button"
          onClick={() => togglePanel("filter")}
          class={`p-2 -ml-2 rounded-full transition relative ${
            activePanel() === "filter" || listFilter() !== DEFAULT_LIST_FILTER
              ? "bg-stone-800 text-white"
              : "text-stone-500 hover:bg-stone-200"
          }`}
          aria-label="Open filters"
          aria-pressed={activePanel() === "filter"}
        >
          <Filter class="w-5 h-5" />
        </button>

        <div class="flex gap-2">
          <button
            type="button"
            onClick={() => togglePanel("sort")}
            class={`p-2 rounded-full transition ${
              activePanel() === "sort" || listSortMode() !== DEFAULT_LIST_SORT_MODE
                ? "bg-stone-800 text-white"
                : "text-stone-500 hover:bg-stone-200"
            }`}
            aria-label="Open sorting"
            aria-pressed={activePanel() === "sort"}
          >
            <ArrowDownWideNarrow class="w-5 h-5" />
          </button>
          <A
            href="/settings"
            class="p-2 -mr-2 rounded-full hover:bg-stone-200 transition text-stone-500"
            aria-label="Open settings"
          >
            <Settings2 class="w-5 h-5" />
          </A>
        </div>
      </header>

      <div class="flex-none px-4 pb-2">
        <div class="w-full max-w-xl mx-auto flex gap-2 overflow-x-auto no-scrollbar">
          <For each={workspaces()}>
            {(workspace) => (
              <button
                type="button"
                onClick={() => void selectWorkspace(workspace.id)}
                class={`shrink-0 rounded-full border px-3 py-1.5 text-sm font-medium transition-colors ${
                  selectedWorkspaceId() === workspace.id
                    ? "border-stone-800 bg-stone-800 text-white"
                    : "border-stone-200 bg-white text-stone-500 hover:border-stone-300 hover:text-stone-700"
                }`}
              >
                {workspace.name}
              </button>
            )}
          </For>
        </div>
      </div>

      <div class="flex-none px-4 pb-3">
        <div class="w-full max-w-xl mx-auto rounded-2xl border border-stone-200 bg-white/80 px-4 py-3 text-sm text-stone-500">
          <div class="flex items-center gap-2">
            <span>{FILTER_LABELS[listFilter()]}</span>
            <span class="text-stone-300">/</span>
            <span>{SORT_LABELS[listSortMode()]}</span>
          </div>

          <Show when={activePanel() === "filter"}>
            <div class="mt-3 flex flex-wrap gap-2">
              <For each={LIST_FILTER_OPTIONS}>
                {(option) => (
                  <button
                    type="button"
                    onClick={() => applyFilter(option)}
                    class={`rounded-full border px-3 py-1.5 font-medium transition-colors ${
                      listFilter() === option
                        ? "border-stone-800 bg-stone-800 text-white"
                        : "border-stone-200 bg-stone-50 text-stone-500 hover:border-stone-300 hover:text-stone-700"
                    }`}
                  >
                    {FILTER_LABELS[option]}
                  </button>
                )}
              </For>
            </div>
          </Show>

          <Show when={activePanel() === "sort"}>
            <div class="mt-3 space-y-3">
              <div class="flex flex-wrap gap-2">
                <For each={LIST_SORT_MODE_OPTIONS}>
                  {(option) => (
                    <button
                      type="button"
                      onClick={() => applySort(option)}
                      class={`rounded-full border px-3 py-1.5 font-medium transition-colors ${
                        listSortMode() === option
                          ? "border-stone-800 bg-stone-800 text-white"
                          : "border-stone-200 bg-stone-50 text-stone-500 hover:border-stone-300 hover:text-stone-700"
                      }`}
                    >
                      {SORT_LABELS[option]}
                    </button>
                  )}
                </For>
              </div>
              <p class="text-xs text-stone-400">
                Manual keeps drag ordering. Due date uses derived ordering with undated tasks last.
              </p>
            </div>
          </Show>
        </div>
      </div>

      <main
        class="flex-1 overflow-y-auto px-4 pb-40 scroll-smooth w-full max-w-xl mx-auto"
        onScroll={handleScroll}
      >
        <Show when={listSortMode() === "due-date"}>
          <div class="mb-3 rounded-2xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">
            Due date sort is derived. Switch back to manual sort to reorder tasks.
          </div>
        </Show>

        <TasksList
          tasks={visibleTasks()}
          emptyState={<div class="p-4 text-center text-stone-400">{emptyStateMessage()}</div>}
        />
      </main>

      <TaskPrompt visible={fabVisible()} />
    </div>
  );
}

import { A } from "@solidjs/router";
import ArrowLeft from "lucide-solid/icons/arrow-left";
import { Show, createMemo, createSignal, onMount } from "solid-js";
import { QRDisplay } from "~/components/DevicePairing";
import {
  buildPairingHash,
  buildPairingUrl,
  clearPairingHash,
  parseVaultKeyFromHash,
} from "~/lib/pairing";
import { initializeSync } from "~/lib/sync";
import {
  createVault,
  initializeVaultStore,
  joinVault,
  vaultState,
} from "~/stores/vaultStore";

type BusyAction = "create" | "join" | "copy" | null;

export default function PairPage() {
  const [busyAction, setBusyAction] = createSignal<BusyAction>(null);
  const [currentOrigin, setCurrentOrigin] = createSignal("");
  const [detectedHash, setDetectedHash] = createSignal<string | null>(null);
  const [pendingVaultKey, setPendingVaultKey] = createSignal<string | null>(null);
  const [errorMessage, setErrorMessage] = createSignal<string | null>(null);
  const [copyMessage, setCopyMessage] = createSignal<string | null>(null);

  onMount(async () => {
    await initializeVaultStore();
    setCurrentOrigin(window.location.origin);
    setDetectedHash(window.location.hash || null);
    setPendingVaultKey(parseVaultKeyFromHash(window.location.hash));
  });

  const joinUrl = createMemo(() => {
    if (!vaultState.vaultKey || !currentOrigin()) {
      return null;
    }

    return buildPairingUrl(currentOrigin(), vaultState.vaultKey);
  });

  const joinHash = createMemo(() => {
    if (!vaultState.vaultKey) {
      return null;
    }

    return buildPairingHash(vaultState.vaultKey);
  });

  const isSameVault = createMemo(() => {
    return Boolean(
      pendingVaultKey() &&
      vaultState.vaultKey &&
      pendingVaultKey() === vaultState.vaultKey
    );
  });

  const canReplaceCurrentVault = createMemo(() => {
    return Boolean(pendingVaultKey() && vaultState.isPaired && !isSameVault());
  });

  const handleCreateVault = async () => {
    setBusyAction("create");
    setErrorMessage(null);

    try {
      await createVault();
      await initializeSync();
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : "Failed to create vault");
    } finally {
      setBusyAction(null);
    }
  };

  const handleJoinVault = async () => {
    const vaultKey = pendingVaultKey();

    if (!vaultKey) {
      return;
    }

    if (canReplaceCurrentVault()) {
      const shouldReplace = window.confirm(
        "This device is already paired with a different vault. Replace the current vault on this device?"
      );

      if (!shouldReplace) {
        return;
      }
    }

    setBusyAction("join");
    setErrorMessage(null);

    try {
      await joinVault(vaultKey);
      clearPairingHash();
      setDetectedHash(null);
      setPendingVaultKey(null);
      await initializeSync();
      window.location.href = "/";
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : "Failed to join vault");
    } finally {
      setBusyAction(null);
    }
  };

  const handleCopyLink = async () => {
    if (!joinUrl()) {
      return;
    }

    setBusyAction("copy");
    setCopyMessage(null);

    try {
      await navigator.clipboard.writeText(joinUrl()!);
      setCopyMessage("Link copied.");
    } catch {
      setCopyMessage("Copy failed. You can copy it manually from the field below.");
    } finally {
      setBusyAction(null);
    }
  };

  return (
    <div class="min-h-screen bg-[#F9F9F8] p-4 text-stone-700">
      <header class="mb-8 flex items-center gap-4 pt-4">
        <A href="/" class="rounded-full p-2 text-stone-500 transition hover:bg-stone-200">
          <ArrowLeft class="h-5 w-5" />
        </A>
        <h1 class="text-2xl font-light tracking-tight text-stone-800">Device Pairing</h1>
      </header>

      <div class="mx-auto flex max-w-md flex-col gap-6">
        <Show when={pendingVaultKey()}>
          <section class="rounded-2xl border border-stone-200 bg-white p-6 shadow-sm">
            <div class="space-y-3">
              <h2 class="text-lg font-medium text-stone-900">Vault link detected</h2>
              <Show when={isSameVault()}>
                <p class="text-sm text-stone-600">
                  This device is already paired with the vault from this link.
                </p>
              </Show>
              <Show when={!isSameVault() && !canReplaceCurrentVault()}>
                <p class="text-sm text-stone-600">
                  This link contains a vault secret in the URL hash. Join from this browser without using the camera.
                </p>
              </Show>
              <Show when={canReplaceCurrentVault()}>
                <p class="text-sm text-amber-700">
                  This device is already paired with another vault. Replacing it requires confirmation.
                </p>
              </Show>
              <p class="break-all rounded-xl bg-stone-100 px-3 py-2 font-mono text-xs text-stone-600">
                {detectedHash() || buildPairingHash(pendingVaultKey()!)}
              </p>
              <div class="flex gap-3">
                <Show when={!isSameVault()}>
                  <button
                    type="button"
                    onClick={handleJoinVault}
                    disabled={busyAction() === "join"}
                    class="rounded-xl bg-stone-900 px-4 py-2 text-sm font-medium text-white transition hover:bg-stone-700 disabled:cursor-not-allowed disabled:bg-stone-400"
                  >
                    {busyAction() === "join"
                      ? "Joining..."
                      : canReplaceCurrentVault()
                        ? "Replace current vault"
                        : "Join this vault"}
                  </button>
                </Show>
                <button
                  type="button"
                  onClick={() => {
                    clearPairingHash();
                    setDetectedHash(null);
                    setPendingVaultKey(null);
                  }}
                  class="rounded-xl border border-stone-300 px-4 py-2 text-sm font-medium text-stone-700 transition hover:bg-stone-100"
                >
                  Dismiss link
                </button>
              </div>
            </div>
          </section>
        </Show>

        <Show when={!vaultState.isPaired}>
          <section class="rounded-2xl border border-stone-200 bg-white p-6 shadow-sm">
            <div class="space-y-4">
              <div class="space-y-2">
                <h2 class="text-lg font-medium text-stone-900">Create your first vault</h2>
                <p class="text-sm text-stone-600">
                  Start pairing on this device, then share the QR code or link with another device.
                </p>
              </div>
              <button
                type="button"
                onClick={handleCreateVault}
                disabled={busyAction() === "create"}
                class="w-full rounded-xl bg-stone-900 px-4 py-3 text-sm font-medium text-white transition hover:bg-stone-700 disabled:cursor-not-allowed disabled:bg-stone-400"
              >
                {busyAction() === "create" ? "Creating vault..." : "Create vault"}
              </button>
            </div>
          </section>
        </Show>

        <Show when={vaultState.isPaired && joinUrl()}>
          <section class="rounded-2xl border border-stone-200 bg-white p-6 shadow-sm">
            <div class="space-y-5">
              <div class="space-y-2 text-center">
                <h2 class="text-lg font-medium text-stone-900">Share this vault</h2>
                <p class="text-sm text-stone-600">
                  Open this link on another device or scan the QR code. The vault secret stays in the URL hash.
                </p>
              </div>

              <QRDisplay joinUrl={joinUrl()!} />

              <div class="space-y-3">
                <label class="block text-xs font-medium uppercase tracking-wide text-stone-500">
                  Full join link
                </label>
                <input
                  readOnly
                  value={joinUrl()!}
                  class="w-full rounded-xl border border-stone-300 bg-stone-50 px-3 py-2 text-sm text-stone-700"
                />
                <button
                  type="button"
                  onClick={handleCopyLink}
                  disabled={busyAction() === "copy"}
                  class="w-full rounded-xl border border-stone-300 px-4 py-2 text-sm font-medium text-stone-700 transition hover:bg-stone-100 disabled:cursor-not-allowed disabled:text-stone-400"
                >
                  {busyAction() === "copy" ? "Copying..." : "Copy full link"}
                </button>
                <Show when={copyMessage()}>
                  <p class="text-sm text-stone-500">{copyMessage()}</p>
                </Show>
              </div>

              <div class="space-y-2">
                <h3 class="text-xs font-medium uppercase tracking-wide text-stone-500">
                  Hash secret format
                </h3>
                <p class="break-all rounded-xl bg-stone-100 px-3 py-2 font-mono text-xs text-stone-600">
                  {joinHash()}
                </p>
              </div>
            </div>
          </section>
        </Show>

        <Show when={errorMessage()}>
          <p class="rounded-2xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
            {errorMessage()}
          </p>
        </Show>

        <section class="rounded-2xl bg-blue-50/50 p-6 text-sm text-stone-600">
          <div class="space-y-3">
            <h3 class="font-semibold text-stone-800">How pairing works now</h3>
            <p>
              Create a vault on the first device, then open the join link on the next device. Camera access is no longer required for the default flow.
            </p>
            <p>
              The vault secret lives in <span class="font-mono text-xs">#vault=...</span>, so it stays client-side during normal routing.
            </p>
          </div>
        </section>
      </div>
    </div>
  );
}

import { createSignal, For, onMount, Show } from "solid-js";
import { A } from "@solidjs/router";
import ArrowLeft from "lucide-solid/icons/arrow-left";
import { vaultState } from "~/stores/vaultStore";
import { syncStateStore, syncNow } from "~/lib/sync";
import { isOnline } from "~/stores/networkStore";
import {
  breakdownGranularity,
  BREAKDOWN_GRANULARITY_OPTIONS,
  setBreakdownGranularity,
} from "~/stores/preferencesStore";
import {
  createWorkspace,
  renameWorkspace,
  selectedWorkspaceId,
  selectWorkspace,
  workspaces,
} from "~/stores/taskStore";

type StorageStatus = "checking" | "persisted" | "not-persisted" | "unavailable";

export default function SettingsPage() {
  const [isSyncing, setIsSyncing] = createSignal(false);
  const [storageStatus, setStorageStatus] = createSignal<StorageStatus>("checking");
  const [isRequestingStorage, setIsRequestingStorage] = createSignal(false);

  const refreshStorageStatus = async () => {
    if (typeof navigator === "undefined" || !navigator.storage?.persisted) {
      setStorageStatus("unavailable");
      return;
    }

    try {
      const persisted = await navigator.storage.persisted();
      setStorageStatus(persisted ? "persisted" : "not-persisted");
    } catch (error) {
      console.warn("Failed to read persistent storage status:", error);
      setStorageStatus("unavailable");
    }
  };

  onMount(async () => {
    await refreshStorageStatus();
  });

  const promptForWorkspaceName = (message: string, initialValue = "") => {
    if (typeof window === "undefined") {
      return null;
    }

    const nextName = window.prompt(message, initialValue)?.trim();
    return nextName ? nextName : null;
  };

  const handleCreateWorkspace = async () => {
    const name = promptForWorkspaceName("Name the new workspace");
    if (!name) {
      return;
    }

    await createWorkspace(name);
  };

  const handleRenameWorkspace = async (workspaceId: string, currentName: string) => {
    const nextName = promptForWorkspaceName("Rename workspace", currentName);
    if (!nextName || nextName === currentName) {
      return;
    }

    await renameWorkspace(workspaceId, nextName);
  };

  const handleSyncNow = async () => {
    setIsSyncing(true);
    try {
      await syncNow();
    } catch (error) {
      console.error("Sync failed:", error);
    } finally {
      setIsSyncing(false);
    }
  };

  const getSyncStatus = () => {
    if (!vaultState.isPaired) return "offline";
    if (syncStateStore.status === "syncing" || isSyncing()) return "syncing";
    if (syncStateStore.lastSyncTimestamp) return "synced";
    return "idle";
  };

  const formatLastSync = () => {
    if (!syncStateStore.lastSyncTimestamp) return "Never";
    const date = new Date(syncStateStore.lastSyncTimestamp);
    return date.toLocaleString();
  };

  const handleRequestPersistentStorage = async () => {
    if (typeof navigator === "undefined" || !navigator.storage?.persist) {
      setStorageStatus("unavailable");
      return;
    }

    setIsRequestingStorage(true);

    try {
      await navigator.storage.persist();
      await refreshStorageStatus();
    } catch (error) {
      console.warn("Failed to request persistent storage:", error);
      await refreshStorageStatus();
    } finally {
      setIsRequestingStorage(false);
    }
  };

  const storageLabel = () => {
    if (storageStatus() === "persisted") {
      return "Enabled";
    }

    if (storageStatus() === "not-persisted") {
      return "Not granted";
    }

    if (storageStatus() === "checking") {
      return "Checking";
    }

    return "Unavailable";
  };

  const storageDescription = () => {
    if (storageStatus() === "persisted") {
      return "This browser was explicitly asked to protect local task data from eviction.";
    }

    if (storageStatus() === "not-persisted") {
      return "Local data still stays on this device, but the browser may evict it under storage pressure unless you request stronger protection.";
    }

    if (storageStatus() === "checking") {
      return "Checking browser storage guarantees.";
    }

    return "This browser does not expose persistent storage diagnostics.";
  };

  return (
    <div class="min-h-screen bg-[#F9F9F8] text-stone-700 p-4">
      <header class="flex items-center gap-4 mb-8 pt-4">
        <A href="/" class="p-2 rounded-full hover:bg-stone-200 transition text-stone-500">
          <ArrowLeft class="w-5 h-5" />
        </A>
        <h1 class="text-2xl font-light tracking-tight text-stone-800">Settings</h1>
      </header>

      <div class="max-w-md mx-auto space-y-8">
        <div class="bg-white rounded-2xl p-6 shadow-sm border border-stone-200/60 space-y-4">
          <div class="flex justify-between items-center">
            <div>
              <h2 class="text-lg font-medium text-stone-800">Workspaces</h2>
              <p class="text-stone-400 text-xs">Choose the active workspace and manage names.</p>
            </div>
            <button
              type="button"
              onClick={() => void handleCreateWorkspace()}
              class="px-4 py-2 bg-stone-800 text-white rounded-lg text-sm font-medium hover:bg-black transition-colors"
            >
              New
            </button>
          </div>

          <div class="space-y-3">
            <For each={workspaces()}>
              {(workspace) => (
                <div class="flex items-center justify-between rounded-xl border border-stone-200 px-4 py-3">
                  <div class="min-w-0">
                    <span class="text-stone-700 font-medium block truncate">{workspace.name}</span>
                    <Show when={selectedWorkspaceId() === workspace.id}>
                      <span class="text-stone-400 text-xs">Current workspace</span>
                    </Show>
                  </div>

                  <div class="flex items-center gap-2">
                    <button
                      type="button"
                      onClick={() => void selectWorkspace(workspace.id)}
                      class={`px-3 py-1.5 rounded-lg text-sm transition-colors ${
                        selectedWorkspaceId() === workspace.id
                          ? "bg-stone-800 text-white"
                          : "bg-stone-100 text-stone-600 hover:bg-stone-200"
                      }`}
                    >
                      {selectedWorkspaceId() === workspace.id ? "Current" : "Use"}
                    </button>
                    <button
                      type="button"
                      onClick={() => void handleRenameWorkspace(workspace.id, workspace.name)}
                      class="px-3 py-1.5 rounded-lg bg-white text-sm text-stone-500 hover:bg-stone-100 transition-colors"
                    >
                      Rename
                    </button>
                  </div>
                </div>
              )}
            </For>
          </div>
        </div>

        <div class="bg-white rounded-2xl p-6 shadow-sm border border-stone-200/60 space-y-6">
          <h2 class="text-lg font-medium text-stone-800">Sync & Devices</h2>

          <div class="flex justify-between items-center">
            <div>
              <span class="text-stone-700 font-medium block">Device Pairing</span>
              <span class="text-stone-400 text-xs">
                {vaultState.isPaired
                  ? "Paired. Add more devices to sync."
                  : "Not paired. Pair to enable sync."}
              </span>
            </div>
            <A href="/pair" class="px-4 py-2 bg-stone-100 rounded-lg text-sm text-stone-600 hover:bg-stone-200 font-medium transition-colors">
              {vaultState.isPaired ? "Manage" : "Pair"}
            </A>
          </div>

          <Show when={vaultState.isPaired}>
            <div class="flex justify-between items-center">
              <div>
                <span class="text-stone-700 font-medium block">Device ID</span>
                <span class="text-stone-400 text-xs">Your unique identifier</span>
              </div>
              <code class="text-xs bg-stone-100 px-2 py-1 rounded text-stone-600 max-w-[120px] truncate">
                {vaultState.deviceId}
              </code>
            </div>
          </Show>

          <hr class="border-stone-100" />

          <div class="flex justify-between items-center">
            <div>
              <span class="text-stone-700 font-medium block">Sync Status</span>
              <span class="text-stone-400 text-xs">Last: {formatLastSync()}</span>
            </div>
            <span class={`px-3 py-1 rounded-full text-xs font-medium ${
              getSyncStatus() === "synced" ? "bg-green-100 text-green-700" :
              getSyncStatus() === "syncing" ? "bg-blue-100 text-blue-700" :
              "bg-stone-100 text-stone-500"
            }`}>
              {getSyncStatus()}
            </span>
          </div>

          <Show when={vaultState.isPaired}>
            <>
              <hr class="border-stone-100" />
              <div class="flex justify-between items-center gap-4">
                <div>
                  <span class="text-stone-700 font-medium block">Manual Sync</span>
                  <span class="text-stone-400 text-xs">
                    {isOnline()
                      ? "Force sync now"
                      : "Offline changes stay queued on this device until you reconnect."}
                  </span>
                </div>
                <button
                  type="button"
                  class="px-4 py-2 bg-stone-800 text-white rounded-lg text-sm font-medium hover:bg-black transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  onClick={handleSyncNow}
                  disabled={isSyncing() || !isOnline()}
                >
                  {isSyncing() ? "Syncing..." : "Sync Now"}
                </button>
              </div>
            </>
          </Show>
        </div>

        <div class="bg-white rounded-2xl p-6 shadow-sm border border-stone-200/60 space-y-4">
          <h2 class="text-lg font-medium text-stone-800">Task Breakdown</h2>
          <div class="space-y-3">
            <div>
              <span class="text-stone-700 font-medium block">Default detail level</span>
              <span class="text-stone-400 text-xs">Used when AI breakdown is turned on in the composer</span>
            </div>

            <div class="grid grid-cols-3 gap-2">
              <For each={BREAKDOWN_GRANULARITY_OPTIONS}>
                {(level) => (
                  <button
                    type="button"
                    onClick={() => setBreakdownGranularity(level)}
                    class={`rounded-xl border px-3 py-2 text-sm font-medium capitalize transition-colors ${
                      breakdownGranularity() === level
                        ? "border-stone-800 bg-stone-800 text-white"
                        : "border-stone-200 bg-stone-50 text-stone-500 hover:border-stone-300 hover:text-stone-700"
                    }`}
                  >
                    {level}
                  </button>
                )}
              </For>
            </div>
          </div>
        </div>

        <div class="bg-white rounded-2xl p-6 shadow-sm border border-stone-200/60 space-y-4">
          <h2 class="text-lg font-medium text-stone-800">Storage</h2>
          <div class="flex justify-between items-start gap-4">
            <div class="space-y-2">
              <span class="text-stone-700 font-medium block">Persistent local data</span>
              <span class="text-stone-400 text-xs">{storageDescription()}</span>
              <p class="text-stone-400 text-xs">
                This option only asks the browser to keep your offline task data more reliably on this device. It does not turn on sync or upload anything.
              </p>
            </div>
            <span class={`px-3 py-1 rounded-full text-xs font-medium ${
              storageStatus() === "persisted"
                ? "bg-green-100 text-green-700"
                : storageStatus() === "not-persisted"
                  ? "bg-amber-100 text-amber-800"
                  : "bg-stone-100 text-stone-500"
            }`}>
              {storageLabel()}
            </span>
          </div>
          <Show when={storageStatus() === "not-persisted"}>
            <button
              type="button"
              onClick={() => void handleRequestPersistentStorage()}
              disabled={isRequestingStorage()}
              class="w-full rounded-xl bg-stone-800 px-4 py-3 text-sm font-medium text-white transition-colors hover:bg-black disabled:cursor-not-allowed disabled:opacity-50"
            >
              {isRequestingStorage() ? "Requesting..." : "Request Persistent Storage"}
            </button>
          </Show>
        </div>
      </div>
    </div>
  );
}

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";

describe("networkStore", () => {
  let originalOnLine: boolean;
  let listeners: Record<string, Set<EventListener>>;

  beforeEach(() => {
    originalOnLine = navigator.onLine;
    listeners = { online: new Set(), offline: new Set() };

    vi.spyOn(window, "addEventListener").mockImplementation((event: string, handler: EventListener) => {
      if (listeners[event]) listeners[event].add(handler);
    });
  });

  afterEach(() => {
    vi.restoreAllMocks();
    Object.defineProperty(navigator, "onLine", { value: originalOnLine, configurable: true });
  });

  it("5.1 AI button should be disabled when offline (isOnline returns false)", async () => {
    Object.defineProperty(navigator, "onLine", { value: false, configurable: true });
    // Re-import to get fresh module with navigator.onLine = false
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    expect(isOnline()).toBe(false);
  });

  it("5.2 Sync button should be disabled when offline (isOnline returns false)", async () => {
    Object.defineProperty(navigator, "onLine", { value: false, configurable: true });
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    // When isOnline() is false, sync button disabled condition (isSyncing() || !isOnline()) is true
    expect(!isOnline()).toBe(true);
  });

  it("5.3 Offline banner appears when offline (isOnline is false)", async () => {
    Object.defineProperty(navigator, "onLine", { value: false, configurable: true });
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    // Banner show condition: !isOnline()
    expect(!isOnline()).toBe(true);
  });

  it("5.4 Banner disappears when online (isOnline is true)", async () => {
    Object.defineProperty(navigator, "onLine", { value: true, configurable: true });
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    expect(!isOnline()).toBe(false);
  });

  it("5.5 isOnline initializes from navigator.onLine", async () => {
    Object.defineProperty(navigator, "onLine", { value: true, configurable: true });
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    expect(isOnline()).toBe(true);
  });

  it("5.6-5.9 Local operations are unaffected by offline status (isOnline is independent of task store)", async () => {
    // Local operations (add, edit, complete, delete, reorder) go through taskStore
    // which uses local cr-sqlite — no network dependency.
    // networkStore only gates UI buttons; it does not block taskStore functions.
    Object.defineProperty(navigator, "onLine", { value: false, configurable: true });
    vi.resetModules();
    const { isOnline } = await import("./networkStore");
    expect(isOnline()).toBe(false);
    // taskStore functions remain callable regardless of isOnline — no guard exists there.
  });
});

import { createSignal } from "solid-js";
import { isServer } from "solid-js/web";

const [isOnline, setIsOnline] = createSignal(true);

if (!isServer) {
  setIsOnline(navigator.onLine);
  window.addEventListener("online", () => setIsOnline(true));
  window.addEventListener("offline", () => setIsOnline(false));
}

export { isOnline };

import { beforeEach, describe, expect, it, vi } from "vitest";

describe("preferencesStore", () => {
  let storage = new Map<string, string>();

  beforeEach(() => {
    vi.resetModules();
    storage = new Map<string, string>();
    Object.defineProperty(window, "localStorage", {
      configurable: true,
      value: {
        getItem: (key: string) => storage.get(key) ?? null,
        setItem: (key: string, value: string) => {
          storage.set(key, value);
        },
      },
    });
  });

  it("falls back to medium for missing or invalid stored values", async () => {
    const { parseBreakdownGranularity, DEFAULT_BREAKDOWN_GRANULARITY } = await import("./preferencesStore");

    expect(parseBreakdownGranularity(null)).toBe(DEFAULT_BREAKDOWN_GRANULARITY);
    expect(parseBreakdownGranularity("unexpected")).toBe(DEFAULT_BREAKDOWN_GRANULARITY);
  });

  it("initializes from local storage when a valid preference exists", async () => {
    window.localStorage.setItem("microstep:breakdown-granularity", "high");

    const { breakdownGranularity } = await import("./preferencesStore");

    expect(breakdownGranularity()).toBe("high");
  });

  it("persists updates to local storage", async () => {
    const {
      breakdownGranularity,
      BREAKDOWN_GRANULARITY_STORAGE_KEY,
      setBreakdownGranularity,
    } = await import("./preferencesStore");

    setBreakdownGranularity("low");

    expect(breakdownGranularity()).toBe("low");
    expect(window.localStorage.getItem(BREAKDOWN_GRANULARITY_STORAGE_KEY)).toBe("low");
  });
});

import { createSignal } from "solid-js";
import { isServer } from "solid-js/web";

export type BreakdownGranularity = "low" | "medium" | "high";
export type ListFilter = "all" | "active" | "completed" | "stalled";
export type ListSortMode = "manual" | "due-date";

export const BREAKDOWN_GRANULARITY_STORAGE_KEY = "microstep:breakdown-granularity";
export const DEFAULT_BREAKDOWN_GRANULARITY: BreakdownGranularity = "medium";
export const BREAKDOWN_GRANULARITY_OPTIONS: BreakdownGranularity[] = ["low", "medium", "high"];
export const LIST_FILTER_STORAGE_KEY = "microstep:list-filter";
export const DEFAULT_LIST_FILTER: ListFilter = "all";
export const LIST_FILTER_OPTIONS: ListFilter[] = ["all", "active", "completed", "stalled"];
export const LIST_SORT_MODE_STORAGE_KEY = "microstep:list-sort-mode";
export const DEFAULT_LIST_SORT_MODE: ListSortMode = "manual";
export const LIST_SORT_MODE_OPTIONS: ListSortMode[] = ["manual", "due-date"];

export const parseBreakdownGranularity = (value: string | null): BreakdownGranularity => {
  if (value === "low" || value === "medium" || value === "high") {
    return value;
  }

  return DEFAULT_BREAKDOWN_GRANULARITY;
};

export const parseListFilter = (value: string | null): ListFilter => {
  if (value === "all" || value === "active" || value === "completed" || value === "stalled") {
    return value;
  }

  return DEFAULT_LIST_FILTER;
};

export const parseListSortMode = (value: string | null): ListSortMode => {
  if (value === "manual" || value === "due-date") {
    return value;
  }

  return DEFAULT_LIST_SORT_MODE;
};

const readPreference = <T>(storageKey: string, parser: (value: string | null) => T, fallback: T) => {
  if (isServer || typeof window === "undefined") {
    return fallback;
  }

  try {
    return parser(window.localStorage.getItem(storageKey));
  } catch (error) {
    console.warn(`Failed to read preference for ${storageKey}:`, error);
    return fallback;
  }
};

const writePreference = (storageKey: string, value: string) => {
  if (isServer || typeof window === "undefined") {
    return;
  }

  try {
    window.localStorage.setItem(storageKey, value);
  } catch (error) {
    console.warn(`Failed to persist preference for ${storageKey}:`, error);
  }
};

const [breakdownGranularity, setBreakdownGranularitySignal] = createSignal<BreakdownGranularity>(
  readPreference(
    BREAKDOWN_GRANULARITY_STORAGE_KEY,
    parseBreakdownGranularity,
    DEFAULT_BREAKDOWN_GRANULARITY,
  )
);
const [listFilter, setListFilterSignal] = createSignal<ListFilter>(
  readPreference(LIST_FILTER_STORAGE_KEY, parseListFilter, DEFAULT_LIST_FILTER)
);
const [listSortMode, setListSortModeSignal] = createSignal<ListSortMode>(
  readPreference(LIST_SORT_MODE_STORAGE_KEY, parseListSortMode, DEFAULT_LIST_SORT_MODE)
);

export { breakdownGranularity };
export { listFilter, listSortMode };

export const setBreakdownGranularity = (value: BreakdownGranularity) => {
  setBreakdownGranularitySignal(value);
  writePreference(BREAKDOWN_GRANULARITY_STORAGE_KEY, value);
};

export const setListFilter = (value: ListFilter) => {
  setListFilterSignal(value);
  writePreference(LIST_FILTER_STORAGE_KEY, value);
};

export const setListSortMode = (value: ListSortMode) => {
  setListSortModeSignal(value);
  writePreference(LIST_SORT_MODE_STORAGE_KEY, value);
};

import { describe, it, expect } from "vitest";
import {
  DEFAULT_WORKSPACE_ID,
  isStalled,
  resolveSelectedWorkspaceId,
  STALE_THRESHOLD_MS,
  type Task,
  type Workspace,
} from "./taskStore";

const makeTask = (overrides: Partial<Task> = {}): Task => ({
  id: "test-id",
  parentId: null,
  workspaceId: DEFAULT_WORKSPACE_ID,
  text: "Test task",
  completed: false,
  createdAt: Date.now(),
  updatedAt: Date.now(),
  dueAt: null,
  rank: "0|aaa:",
  isStalled: false,
  ...overrides,
});

describe("Task updatedAt", () => {
  it("new task has updatedAt == createdAt", () => {
    const now = Date.now();
    const task = makeTask({ createdAt: now, updatedAt: now });
    expect(task.updatedAt).toBe(task.createdAt);
  });

  it("editing task text updates updatedAt", () => {
    const created = Date.now() - 1000;
    const updated = Date.now();
    const task = makeTask({ createdAt: created, updatedAt: updated });
    expect(task.updatedAt).toBeGreaterThan(task.createdAt);
  });

  it("toggling completion updates updatedAt", () => {
    const created = Date.now() - 1000;
    const updated = Date.now();
    const task = makeTask({ createdAt: created, updatedAt: updated, completed: true });
    expect(task.updatedAt).toBeGreaterThan(task.createdAt);
  });

  it("moving task updates updatedAt", () => {
    const created = Date.now() - 1000;
    const updated = Date.now();
    const task = makeTask({ createdAt: created, updatedAt: updated, parentId: "new-parent" });
    expect(task.updatedAt).toBeGreaterThan(task.createdAt);
  });
});

describe("resolveSelectedWorkspaceId", () => {
  const workspaces: Workspace[] = [
    { id: DEFAULT_WORKSPACE_ID, name: "Default", createdAt: 1, updatedAt: 1 },
    { id: "work", name: "Work", createdAt: 2, updatedAt: 2 },
  ];

  it("prefers a persisted workspace when it still exists", () => {
    expect(resolveSelectedWorkspaceId(workspaces, "work")).toBe("work");
  });

  it("falls back to the default workspace when the preference is missing", () => {
    expect(resolveSelectedWorkspaceId(workspaces, "missing")).toBe(DEFAULT_WORKSPACE_ID);
  });
});

describe("isStalled", () => {
  it("returns true for old untouched tasks", () => {
    const oldTime = Date.now() - STALE_THRESHOLD_MS - 1;
    const task = makeTask({ createdAt: oldTime, updatedAt: oldTime });
    expect(isStalled(task)).toBe(true);
  });

  it("returns false for recently created tasks", () => {
    const now = Date.now();
    const task = makeTask({ createdAt: now, updatedAt: now });
    expect(isStalled(task)).toBe(false);
  });

  it("returns false for old but edited tasks", () => {
    const oldTime = Date.now() - STALE_THRESHOLD_MS - 1;
    const task = makeTask({ createdAt: oldTime, updatedAt: Date.now() });
    expect(isStalled(task)).toBe(false);
  });
});

import { createEffect, createMemo, createRoot } from "solid-js";
import { createStore } from "solid-js/store";
import { isServer } from "solid-js/web";
import { LexoRank } from "lexorank";
import { initDb, exec, query, dbVersion } from "~/lib/db";
import { normalizeDueDateValue } from "~/lib/dates";
import { fetchMainViewTasks } from "~/lib/query";

const nanoid = () => {
  const array = new Uint8Array(16);

  crypto.getRandomValues(array);
  return Array.from(array, byte => ('0' + byte.toString(16)).slice(-2)).join('');
}

export type Task = {
  id: string;
  parentId: string | null;
  workspaceId: string;
  text: string;
  completed: boolean;
  createdAt: number;
  updatedAt: number;
  dueAt: number | null;
  rank: string;
  isStalled: boolean;
};

export type Workspace = {
  id: string;
  name: string;
  createdAt: number;
  updatedAt: number;
};

export const STALE_THRESHOLD_MS = 7 * 24 * 60 * 60 * 1000;
export const DEFAULT_WORKSPACE_ID = "default";
const WORKSPACE_STORAGE_KEY = "microstep:selected-workspace-id";

export const isStalled = (task: Task, now: number = Date.now()): boolean =>
  task.updatedAt === task.createdAt && (now - task.createdAt) > STALE_THRESHOLD_MS;

export type TreeNode = Task & {
  children: TreeNode[];
  effectiveDueDate: number | null;
};

const dbRowToTask = (row: any): Task => ({
  id: row.id,
  parentId: row.parent_id,
  workspaceId: row.workspace_id,
  text: row.text,
  completed: Boolean(row.completed),
  createdAt: row.created_at,
  updatedAt: row.updated_at,
  dueAt: row.due_at,
  rank: row.rank,
  isStalled: Boolean(row.is_stalled),
});

const dbRowToWorkspace = (row: any): Workspace => ({
  id: row.id,
  name: row.name,
  createdAt: row.created_at,
  updatedAt: row.updated_at,
});

const readSelectedWorkspacePreference = () => {
  if (isServer || typeof window === "undefined") {
    return null;
  }

  try {
    return window.localStorage.getItem(WORKSPACE_STORAGE_KEY);
  } catch (error) {
    console.warn("Failed to read selected workspace preference:", error);
    return null;
  }
};

const writeSelectedWorkspacePreference = (workspaceId: string | null) => {
  if (isServer || typeof window === "undefined") {
    return;
  }

  try {
    if (workspaceId) {
      window.localStorage.setItem(WORKSPACE_STORAGE_KEY, workspaceId);
      return;
    }

    window.localStorage.removeItem(WORKSPACE_STORAGE_KEY);
  } catch (error) {
    console.warn("Failed to persist selected workspace preference:", error);
  }
};

export const resolveSelectedWorkspaceId = (
  availableWorkspaces: Workspace[],
  preferredWorkspaceId: string | null
) => {
  if (preferredWorkspaceId && availableWorkspaces.some((workspace) => workspace.id === preferredWorkspaceId)) {
    return preferredWorkspaceId;
  }

  const defaultWorkspace = availableWorkspaces.find((workspace) => workspace.id === DEFAULT_WORKSPACE_ID);
  return defaultWorkspace?.id ?? availableWorkspaces[0]?.id ?? null;
};

const compareDueThenRank = (a: Task, b: Task) => {
  const aDue = a.dueAt ?? Number.POSITIVE_INFINITY;
  const bDue = b.dueAt ?? Number.POSITIVE_INFINITY;
  if (aDue !== bDue) return aDue - bDue;
  return a.rank.localeCompare(b.rank);
};

const computeInitialRank = async (
  parentId: string | null,
  dueAt: number | null,
  workspaceId: string
) => {
  let rows: any[];
  if (parentId) {
    rows = await query("SELECT * FROM tasks WHERE parent_id = ?", [parentId]);
  } else {
    rows = await query("SELECT * FROM tasks WHERE parent_id IS NULL AND workspace_id = ?", [workspaceId]);
  }

  if (!rows || !Array.isArray(rows) || rows.length === 0) {
    return LexoRank.middle().toString();
  }

  const siblings = rows.map(dbRowToTask);

  const sorted = siblings.slice().sort(compareDueThenRank);
  const targetIndex = sorted.findIndex((sibling) => {
    const siblingDue = sibling.dueAt ?? Number.POSITIVE_INFINITY;
    const currentDue = dueAt ?? Number.POSITIVE_INFINITY;
    return currentDue < siblingDue;
  });

  const insertIndex = targetIndex === -1 ? sorted.length : targetIndex;
  const prev = sorted[insertIndex - 1];
  const next = sorted[insertIndex];

  if (!prev && !next) {
    return LexoRank.middle().toString();
  }
  if (!prev && next) {
    return LexoRank.parse(next.rank).genPrev().toString();
  }
  if (prev && !next) {
    return LexoRank.parse(prev.rank).genNext().toString();
  }
  return LexoRank.parse(prev.rank).between(LexoRank.parse(next.rank)).toString();
};

const taskStore = createRoot(() => {
  const [state, setState] = createStore({
    tasks: {} as Record<string, Task>,
    expandedTaskIds: {} as Record<string, boolean>,
    workspaces: [] as Workspace[],
    selectedWorkspaceId: null as string | null,
    isSynced: false,
  });

  const setSelectedWorkspace = (workspaceId: string | null) => {
    setState("selectedWorkspaceId", workspaceId);
    writeSelectedWorkspacePreference(workspaceId);
  };

  const refreshWorkspaces = async () => {
    const rows = await query("SELECT * FROM workspaces ORDER BY created_at ASC");
    const nextWorkspaces = Array.isArray(rows) ? rows.map(dbRowToWorkspace) : [];
    setState("workspaces", nextWorkspaces);
    return nextWorkspaces;
  };

  const refreshTasks = async (workspaceId: string | null = state.selectedWorkspaceId) => {
    if (!workspaceId) {
      setState("tasks", {});
      return;
    }

    const rows = await fetchMainViewTasks(workspaceId);
    const taskMap: Record<string, Task> = {};

    if (Array.isArray(rows)) {
      rows.forEach((row: any) => {
        const task = dbRowToTask(row);
        taskMap[task.id] = task;
      });
    }

    setState("tasks", taskMap);
  };

  const refreshWorkspaceState = async (preferredWorkspaceId: string | null) => {
    const availableWorkspaces = await refreshWorkspaces();
    const resolvedWorkspaceId = resolveSelectedWorkspaceId(availableWorkspaces, preferredWorkspaceId);

    if (resolvedWorkspaceId !== state.selectedWorkspaceId) {
      setSelectedWorkspace(resolvedWorkspaceId);
    }

    await refreshTasks(resolvedWorkspaceId);
    return resolvedWorkspaceId;
  };

  // Auto-refresh when db changes via worker broadcast
  createEffect(() => {
    const version = dbVersion();
    if (version > 0) {
      void refreshWorkspaceState(state.selectedWorkspaceId ?? readSelectedWorkspacePreference());
    }
  });

  const initializeTaskStore = async () => {
    if (isServer) return;

    try {
      await initDb();
      await refreshWorkspaceState(readSelectedWorkspacePreference());
      setState("isSynced", true);
    } catch (err) {
      console.error("Failed to initialize task store:", err);
    }
  };

  const tasks = createMemo(() => {
    const tasks = Object.values(state.tasks);
    const nodeMap = new Map<string, TreeNode>();

    tasks.forEach(t => {
      nodeMap.set(t.id, { ...t, children: [], effectiveDueDate: t.dueAt });
    });

    const roots: TreeNode[] = [];

    tasks.forEach(t => {
      const node = nodeMap.get(t.id)!;
      if (t.parentId && nodeMap.has(t.parentId)) {
        nodeMap.get(t.parentId)!.children.push(node);
      } else {
        roots.push(node);
      }
    });

    const processNode = (node: TreeNode): number | null => {
      let minChildDate: number | null = null;

      node.children.forEach(child => {
        const childDate = processNode(child);

        if (childDate !== null) {
          if (minChildDate === null || childDate < minChildDate) {
            minChildDate = childDate;
          }
        }
      });

      if (node.dueAt !== null) {
        node.effectiveDueDate = minChildDate !== null 
          ? Math.min(node.dueAt, minChildDate) 
          : node.dueAt;
      } else {
        node.effectiveDueDate = minChildDate;
      }

      return node.effectiveDueDate;
    };

    roots.forEach(processNode);

    return roots;
  });

  return { state, setState, initializeTaskStore, tasks, refreshTasks, setSelectedWorkspace };
});

const { state, setState, initializeTaskStore, tasks, refreshTasks, setSelectedWorkspace } = taskStore;

export { initializeTaskStore, tasks };
export const workspaces = () => state.workspaces;
export const selectedWorkspaceId = () => state.selectedWorkspaceId;

export const rawTasks = state.tasks;
export const isTaskExpanded = (taskId: string) => Boolean(state.expandedTaskIds[taskId]);
export const setTaskExpanded = (taskId: string, value: boolean) => {
  setState("expandedTaskIds", taskId, value);
};

type NewTaskPayload = {
  content: string;
  dueDate?: string | number | null;
};

export const addTask = async (data: NewTaskPayload, parentId: string | null = null) => {
  const id = nanoid();
  const workspaceId = parentId
    ? (await query<{ workspace_id: string }>("SELECT workspace_id FROM tasks WHERE id = ?", [parentId]))[0]?.workspace_id
    : state.selectedWorkspaceId;

  if (!workspaceId) {
    throw new Error("Cannot create a task without a selected workspace");
  }

  const dueAt = normalizeDueDateValue(data.dueDate);

  const rank = await computeInitialRank(parentId, dueAt, workspaceId);

  const now = Date.now();
  await exec(
    "INSERT INTO tasks (id, parent_id, text, completed, created_at, updated_at, due_at, rank, workspace_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
    [id, parentId, data.content, 0, now, now, dueAt, rank, workspaceId]
  );

  const newTask: Task = {
    id,
    parentId,
    workspaceId,
    text: data.content,
    completed: false,
    createdAt: now,
    updatedAt: now,
    dueAt,
    rank,
    isStalled: false,
  };

  return newTask;
};

export const selectWorkspace = async (workspaceId: string) => {
  if (!state.workspaces.some((workspace) => workspace.id === workspaceId)) {
    return;
  }

  setSelectedWorkspace(workspaceId);
  await refreshTasks(workspaceId);
};

export const createWorkspace = async (name: string) => {
  const trimmedName = name.trim();
  if (!trimmedName) {
    return null;
  }

  const id = nanoid();
  const now = Date.now();

  await exec(
    "INSERT INTO workspaces (id, name, created_at, updated_at) VALUES (?, ?, ?, ?)",
    [id, trimmedName, now, now]
  );

  setSelectedWorkspace(id);
  setState("tasks", {});
  return id;
};

export const renameWorkspace = async (id: string, name: string) => {
  const trimmedName = name.trim();
  if (!trimmedName) {
    return;
  }

  await exec(
    "UPDATE workspaces SET name = ?, updated_at = ? WHERE id = ?",
    [trimmedName, Date.now(), id]
  );
};

export const updateTask = async (id: string, fields: Partial<Task>) => {
  const rows = await query("SELECT * FROM tasks WHERE id = ?", [id]);

  if (!rows || !Array.isArray(rows) || rows.length === 0) return;

  const updates: string[] = [];
  const values: any[] = [];

  if (fields.parentId !== undefined) {
    updates.push("parent_id = ?");
    values.push(fields.parentId);
  }
  if (fields.text !== undefined) {
    updates.push("text = ?");
    values.push(fields.text);
  }
  if (fields.completed !== undefined) {
    updates.push("completed = ?");
    values.push(fields.completed ? 1 : 0);
  }
  if (fields.dueAt !== undefined) {
    updates.push("due_at = ?");
    values.push(fields.dueAt);
  }
  if (fields.rank !== undefined) {
    updates.push("rank = ?");
    values.push(fields.rank);
  }

  if (updates.length) {
    updates.push("updated_at = ?");
    values.push(Date.now());
    values.push(id);
    await exec(`UPDATE tasks SET ${updates.join(", ")} WHERE id = ?`, values);
  }
};

export const moveTask = async (
  taskId: string, 
  newParentId: string | null, 
  prevSiblingRank?: string, 
  nextSiblingRank?: string
) => {
  const rows = await query("SELECT * FROM tasks WHERE id = ?", [taskId]);

  if (!rows || !Array.isArray(rows) || rows.length === 0) return;

  let newRank;
  if (!prevSiblingRank && !nextSiblingRank) {
    newRank = LexoRank.middle().toString();
  } else if (!prevSiblingRank && nextSiblingRank) {
    newRank = LexoRank.parse(nextSiblingRank).genPrev().toString();
  } else if (prevSiblingRank && !nextSiblingRank) {
    newRank = LexoRank.parse(prevSiblingRank).genNext().toString();
  } else {
    newRank = LexoRank.parse(prevSiblingRank!).between(LexoRank.parse(nextSiblingRank!)).toString();
  }

  await exec(
    "UPDATE tasks SET parent_id = ?, rank = ?, updated_at = ? WHERE id = ?",
    [newParentId, newRank, Date.now(), taskId]
  );
};

export const deleteTask = async (id: string) => {
  const toRemove: string[] = [id];
  let found = true;

  while (found) {
    found = false;
    const rows = await query("SELECT * FROM tasks");
    if (Array.isArray(rows)) {
      rows.forEach((row: any) => {
        if (toRemove.includes(row.parent_id) && !toRemove.includes(row.id)) {
          toRemove.push(row.id);
          found = true;
        }
      });
    }
  }

  for (const taskId of toRemove) {
    setTaskExpanded(taskId, false);
    await exec("DELETE FROM tasks WHERE id = ?", [taskId]);
  }
};

import { createStore } from "solid-js/store";
import { generateVaultKey, hashVaultKeyToPath } from "~/lib/crypto";

type VaultState = {
  vaultKey: string | null;
  vaultPath: string | null;
  deviceId: string | null;
  isPaired: boolean;
  requiresRemoteBootstrap: boolean;
};

const VAULT_IDB_NAME = "vault_store";
const VAULT_IDB_VERSION = 1;
const REQUIRES_REMOTE_BOOTSTRAP_KEY = "requiresRemoteBootstrap";

let idb: IDBDatabase | null = null;

const initIndexedDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(VAULT_IDB_NAME, VAULT_IDB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains("vault")) {
        db.createObjectStore("vault", { keyPath: "key" });
      }
    };
  });
};

const setIDBValue = async (key: string, value: any) => {
  if (!idb) {
    idb = await initIndexedDB();
  }

  return new Promise<void>((resolve, reject) => {
    const transaction = idb!.transaction("vault", "readwrite");
    const store = transaction.objectStore("vault");
    const request = store.put({ key, value });

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

const getIDBValue = async <T = any>(key: string): Promise<T | null> => {
  if (!idb) {
    idb = await initIndexedDB();
  }

  return new Promise((resolve, reject) => {
    const transaction = idb!.transaction("vault", "readonly");
    const store = transaction.objectStore("vault");
    const request = store.get(key);

    request.onsuccess = () => {
      const result = request.result;
      resolve(result ? result.value : null);
    };
    request.onerror = () => reject(request.error);
  });
};

const generateDeviceId = (): string => {
  return crypto.randomUUID();
};

const [state, setState] = createStore<VaultState>({
  vaultKey: null,
  vaultPath: null,
  deviceId: null,
  isPaired: false,
  requiresRemoteBootstrap: false,
});

export const initializeVaultStore = async () => {
  const vaultKey = await getIDBValue<string>("vaultKey");
  const deviceId = await getIDBValue<string>("deviceId");
  const requiresRemoteBootstrap = await getIDBValue<boolean>(REQUIRES_REMOTE_BOOTSTRAP_KEY);

  if (!deviceId) {
    const newDeviceId = generateDeviceId();
    await setIDBValue("deviceId", newDeviceId);
    setState({ deviceId: newDeviceId });
  } else {
    setState({ deviceId });
  }

  if (vaultKey) {
    const vaultPath = await hashVaultKeyToPath(vaultKey);
    setState({
      vaultKey,
      vaultPath,
      isPaired: true,
      requiresRemoteBootstrap: Boolean(requiresRemoteBootstrap),
    });
  }
};

export const createVault = async () => {
  const vaultKey = await generateVaultKey();
  const vaultPath = await hashVaultKeyToPath(vaultKey);
  const deviceId = state.deviceId || generateDeviceId();

  await setIDBValue("vaultKey", vaultKey);
  await setIDBValue("deviceId", deviceId);
  await setIDBValue(REQUIRES_REMOTE_BOOTSTRAP_KEY, false);

  setState({
    vaultKey,
    vaultPath,
    deviceId,
    isPaired: true,
    requiresRemoteBootstrap: false,
  });

  return { vaultKey, vaultPath, deviceId };
};

export const joinVault = async (vaultKey: string) => {
  const vaultPath = await hashVaultKeyToPath(vaultKey);
  const deviceId = state.deviceId || generateDeviceId();

  await setIDBValue("vaultKey", vaultKey);
  await setIDBValue("deviceId", deviceId);
  await setIDBValue(REQUIRES_REMOTE_BOOTSTRAP_KEY, true);

  setState({
    vaultKey,
    vaultPath,
    deviceId,
    isPaired: true,
    requiresRemoteBootstrap: true,
  });
};

export const resolveRemoteBootstrap = async () => {
  await setIDBValue(REQUIRES_REMOTE_BOOTSTRAP_KEY, false);
  setState("requiresRemoteBootstrap", false);
};

export const clearVault = async () => {
  await setIDBValue("vaultKey", null);
  await setIDBValue(REQUIRES_REMOTE_BOOTSTRAP_KEY, false);

  setState({
    vaultKey: null,
    vaultPath: null,
    isPaired: false,
    requiresRemoteBootstrap: false,
  });
};

export const vaultState = state;

/// <reference lib="webworker" />

import { cleanupOutdatedCaches, precacheAndRoute } from "workbox-precaching";
import {
  OFFLINE_DOCUMENT_PATHS,
  shouldHandleOfflineNavigation,
  toNavigationCacheKey,
} from "~/lib/serviceWorkerRouting";

declare const self: ServiceWorkerGlobalScope;

const NAVIGATION_CACHE_NAME = "micro-step-navigation-v1";
const ROOT_DOCUMENT_PATH = "/";
const STATIC_PWA_ASSETS = ["/favicon.ico", "/icon-192.png", "/icon-512.png", "/manifest.json"].map((url) => ({
  url,
  revision: null,
}));

const toScopedDocumentUrl = (path: string) => new URL(path, self.registration.scope).toString();

const cacheOfflineDocuments = async () => {
  const cache = await caches.open(NAVIGATION_CACHE_NAME);

  await Promise.all(
    OFFLINE_DOCUMENT_PATHS.map(async (path) => {
      try {
        const url = toScopedDocumentUrl(path);
        const response = await fetch(new Request(url, { cache: "reload" }));

        if (response.ok) {
          await cache.put(url, response.clone());
        }
      } catch {
        // Keep the install alive even if one document cannot be refreshed yet.
      }
    }),
  );
};

const handleNavigation = async (request: Request) => {
  const url = new URL(request.url);
  const cache = await caches.open(NAVIGATION_CACHE_NAME);
  const cacheKey = toScopedDocumentUrl(toNavigationCacheKey(url));
  const rootFallbackKey = toScopedDocumentUrl(ROOT_DOCUMENT_PATH);

  try {
    const response = await fetch(request);

    if (response.ok && response.headers.get("content-type")?.includes("text/html")) {
      await cache.put(cacheKey, response.clone());
    }

    return response;
  } catch {
    const cachedResponse = await cache.match(cacheKey);
    if (cachedResponse) {
      return cachedResponse;
    }

    const rootFallback = await cache.match(rootFallbackKey);
    if (rootFallback) {
      return rootFallback;
    }

    return errorResponse();
  }
};

const errorResponse = () =>
  new Response("Offline content unavailable", {
    status: 503,
    statusText: "Service Unavailable",
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
    },
  });

precacheAndRoute([...self.__WB_MANIFEST, ...STATIC_PWA_ASSETS]);
cleanupOutdatedCaches();

self.addEventListener("install", (event) => {
  self.skipWaiting();
  event.waitUntil(cacheOfflineDocuments());
});

self.addEventListener("activate", (event) => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener("fetch", (event) => {
  const { request } = event;
  const url = new URL(request.url);

  if (!shouldHandleOfflineNavigation(request.mode, url, self.location.origin)) {
    return;
  }

  event.respondWith(handleNavigation(request));
});

import initWasm from "@vlcn.io/crsqlite-wasm";
import type { DbRequest, DbResponse } from "../lib/db.types";

let db: any = null;

const DEFAULT_WORKSPACE_ID = "default";
const DEFAULT_WORKSPACE_NAME = "Default";

const ensureTaskTable = async () => {
  await db.exec(`
    CREATE TABLE IF NOT EXISTS tasks (
      id TEXT NOT NULL PRIMARY KEY DEFAULT '',
      parent_id TEXT,
      text TEXT NOT NULL DEFAULT '',
      completed INTEGER NOT NULL DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT 0,
      updated_at INTEGER,
      due_at INTEGER,
      rank TEXT NOT NULL DEFAULT '',
      workspace_id TEXT,
      site_id BLOB
    );
  `);
};

const ensureTaskWorkspaceColumn = async () => {
  const columns = await db.execO("PRAGMA table_info(tasks)");
  const hasWorkspaceId = Array.isArray(columns)
    && columns.some((column: { name?: string }) => column.name === "workspace_id");

  if (hasWorkspaceId) {
    return;
  }

  await db.exec(`
    SELECT crsql_begin_alter('tasks');
    ALTER TABLE tasks ADD COLUMN workspace_id TEXT;
    SELECT crsql_commit_alter('tasks');
  `);
};

const ensureWorkspaceTable = async () => {
  await db.exec(`
    CREATE TABLE IF NOT EXISTS workspaces (
      id TEXT NOT NULL PRIMARY KEY DEFAULT '',
      name TEXT NOT NULL DEFAULT '',
      created_at INTEGER NOT NULL DEFAULT 0,
      updated_at INTEGER NOT NULL DEFAULT 0,
      site_id BLOB
    );

    SELECT crsql_as_crr('workspaces');
  `);
};

const ensureDefaultWorkspace = async () => {
  const now = Date.now();

  await db.exec(
    "INSERT OR IGNORE INTO workspaces (id, name, created_at, updated_at) VALUES (?, ?, ?, ?)",
    [DEFAULT_WORKSPACE_ID, DEFAULT_WORKSPACE_NAME, now, now]
  );
  await db.exec("UPDATE tasks SET updated_at = created_at WHERE updated_at IS NULL");
  await db.exec(
    "UPDATE tasks SET workspace_id = ? WHERE workspace_id IS NULL OR workspace_id = ''",
    [DEFAULT_WORKSPACE_ID]
  );
};

const ensureSchema = async () => {
  await ensureTaskTable();
  await db.exec("SELECT crsql_as_crr('tasks')");
  await ensureTaskWorkspaceColumn();
  await ensureWorkspaceTable();
  await ensureDefaultWorkspace();
};

const initDb = async () => {
  const sqlite = await initWasm();
  db = await sqlite.open("microstep.db");

  await ensureSchema();
};

self.onmessage = async (event: MessageEvent<DbRequest>) => {
  const msg = event.data;

  try {
    switch (msg.type) {
      case 'init': {
        await initDb();
        self.postMessage({ id: msg.id, type: 'success' } as DbResponse);
        break;
      }
      case 'exec': {
        await db.exec(msg.sql, msg.params);
        self.postMessage({ id: msg.id, type: 'success' } as DbResponse);
        self.postMessage({ type: 'change', table: 'tasks' } as DbResponse);
        break;
      }
      case 'query': {
        const rows = await db.execO(msg.sql, msg.params);
        self.postMessage({ id: msg.id, type: 'success', data: { rows } } as DbResponse);
        break;
      }
      case 'export': {
        const exported = db.export();
        self.postMessage({ id: msg.id, type: 'success', data: { bytes: exported } } as DbResponse);
        break;
      }
      case 'import': {
        const sqlite = await initWasm();
        if (db) await db.close();
        db = await sqlite.open("microstep.db", new Uint8Array(msg.data));
        await ensureSchema();
        self.postMessage({ id: msg.id, type: 'success' } as DbResponse);
        self.postMessage({ type: 'change', table: 'tasks' } as DbResponse);
        break;
      }
    }
  } catch (err: any) {
    if ('id' in msg) {
      self.postMessage({
        id: msg.id,
        type: 'error',
        message: err.message || String(err),
      } as DbResponse);
    }
  }
};

